                    className="transition-all duration-700"
                  />
                  {showBlue && <line x1={(isAscending ? fromNode.x : toNode.x) + nx * offsetDist} y1={(isAscending ? fromNode.y : toNode.y) + ny * offsetDist} x2={(isAscending ? toNode.x : fromNode.x) + nx * offsetDist} y2={(isAscending ? toNode.y : fromNode.y) + ny * offsetDist} stroke="#06b6d4" strokeWidth="3.5" className="liquid-blue-flow" />}
                  {showGreen && <line x1={(isAscending ? toNode.x : fromNode.x) - nx * offsetDist} y1={(isAscending ? toNode.y : fromNode.y) - ny * offsetDist} x2={(isAscending ? fromNode.x : toNode.x) - nx * offsetDist} y2={(isAscending ? fromNode.y : toNode.y) - ny * offsetDist} stroke="#4ade80" strokeWidth="3.5" className="liquid-green-flow" />}
                  {showSilver && <line x1={fromNode.x} y1={fromNode.y} x2={toNode.x} y2={toNode.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />}
                </g>
              );
            })}
            {extraSilverLines.map(([fromId, toId], idx) => {
              const f = KATHARA_GRID_NODES.find(n => n.id === fromId);
              const t = KATHARA_GRID_NODES.find(n => n.id === toId);
              if (!f || !t) return null;
              return (
                <g key={`extra-silver-${idx}`}>
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="rgba(203,213,225,0.4)" strokeWidth="3" />
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />
                </g>
              );
            })}
          </g>

          {showLightning && (
            <g className="pointer-events-none">
              <path d="M 75 20 L 95 60 L 55 100 L 75 140" fill="none" className="lightning-bolt" />
              <path d="M 30 140 L 55 170 L 35 200 L 75 240" fill="none" className="lightning-bolt" />
              <path d="M 120 140 L 95 170 L 115 200 L 75 240" fill="none" className="lightning-bolt" />
            </g>
          )}

          {showExplosion && (
            <g transform="translate(75, 140)" className="pointer-events-none">
              <circle r="12" className="fire-burst" />
              <circle r="8" className="fire-burst" style={{ animationDelay: '0.1s' }} />
            </g>
          )}

          {KATHARA_GRID_NODES.map((node, nodeIdx) => {
            const isFilter = node.id > 12;
            const isHighlighted = highlightedNodes.includes(node.id);
            const displayLabelIdx = isFilter ? -1 : getDisplayIdx(nodeIdx, labelOffset, activeMode);
            const rawLabel = isFilter ? '' : labels[displayLabelIdx];

            // Combined triplet labels as requested
            const filterFullLabel = node.id === 13 ? '△108⚡' : node.id === 14 ? '🔥103🐟' : node.id === 15 ? '⚫110🌳' : null;

            const labelParts = rawLabel ? rawLabel.split('|').map(p => p.trim()) : [];
            const hasMultiple = labelParts.length > 1;
            const isSpineNode = node.x === 75 && node.id <= 12; 
            const isLeftSide = node.x < 75;

            return (
              <g key={node.id} className="transition-all duration-500">
                {isFilter ? (
                  <g>
                    {isHighlighted && <rect x={node.x-28} y={node.y-12} width="56" height="24" rx="4" fill="rgba(6,182,212,0.15)" className="animate-pulse" />}
                    <rect x={node.x-25} y={node.y-10} width="50" height="20" rx="3" className={`filter-junction ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#06b6d4' }} />
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#0891b2"} className="font-mono tracking-tighter" style={{ pointerEvents: 'none' }}>
                      {filterFullLabel}
                    </text>
                  </g>
                ) : (
                  <g>
                    <rect x={node.x-14} y={node.y-14} width="28" height="28" rx="6" className={`junction-box ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#fff' }} />
                    {isHighlighted && <circle cx={node.x} cy={node.y} r={22} fill="url(#activeGrad)" opacity="0.1" className="animate-pulse" />}
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="8" fontWeight="black" fill={isHighlighted ? "#fff" : "#555"}>{node.id}</text>
                    {rawLabel && (
                      <g className="pointer-events-none">
                         {isSpineNode && hasMultiple ? (
                          <>
                            <rect x={node.x - 76} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x - 22} y={node.y} textAnchor="end" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[0]}</text>
                            <rect x={node.x + 18} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x + 22} y={node.y} textAnchor="start" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[1]}</text>
                          </>
                         ) : (
                          <g>
                             <rect x={isLeftSide ? node.x - 76 : node.x + 18} y={node.y - (hasMultiple ? 14 : 9)} width="58" height={hasMultiple ? 28 : 18} rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                             <text x={isLeftSide ? node.x - 22 : node.x + 22} y={node.y} textAnchor={isLeftSide ? "end" : "start"} dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">
                               {hasMultiple ? (<><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="-0.5em">{labelParts[0]}</tspan><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="1.1em">{labelParts[1]}</tspan></>) : rawLabel}
                             </text>
                          </g>
                         )}
                      </g>
                    )}
                  </g>
                )}
              </g>
            );
          })}
        </svg>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#02040a] animate-in fade-in zoom-in duration-500 overflow-y-auto lg:overflow-hidden">
      <aside className="w-full lg:w-[420px] h-fit lg:h-full p-6 lg:p-8 border-b lg:border-r border-white/10 flex flex-col space-y-4 md:space-y-6 bg-black/40 backdrop-blur-xl shrink-0 overflow-visible lg:overflow-y-auto custom-scrollbar">
        <div className="flex justify-between items-start shrink-0">
          <div className="space-y-1">
            <h2 className="text-xl md:text-2xl font-black text-white tracking-tighter uppercase italic leading-tight">
              Photosynthesis:
              <span className="block text-[10px] md:text-sm font-bold tracking-widest text-cyan-400 mt-1 not-italic">
                Harvesting Love and Intelligence in Form
              </span>
            </h2>
            <div className="flex flex-wrap gap-1.5 mt-2">
               {[0, 1, 2, 3].map(n => (
                 <button key={n} onClick={() => handlePreset(n)} className={`w-8 h-8 md:w-9 md:h-9 rounded-lg border font-black text-[9px] md:text-[10px] transition-all ${n === 0 ? 'bg-white/5 border-white/10 text-gray-500' : 'bg-cyan-950/20 border-cyan-500/30 text-cyan-400 hover:bg-cyan-500 hover:text-black'}`}>
                   {n === 0 ? 'CLR' : `P${n}`}
                 </button>
               ))}
               <button onClick={() => handleSyncFromWheel('full')} className="px-2 md:px-3 h-8 md:h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[9px] md:text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 1</button>
               <button onClick={() => handleSyncFromWheel('title')} className="px-2 md:px-3 h-8 md:h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[9px] md:text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 2</button>
            </div>
          </div>
          <button onClick={onClose} className="p-2 md:p-3 rounded-2xl bg-white/5 text-gray-400 hover:text-white transition-all hover:bg-white/10 shrink-0">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 md:h-6 md:w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        {/* Scrollable inputs container for mobile */}
        <div className="flex-1 space-y-3 md:space-y-4 pr-1 max-h-[300px] lg:max-h-none overflow-y-auto lg:overflow-visible custom-scrollbar">
          {labels.map((label, idx) => {
            let mappedNodeId = -1;
            for(let ni=0; ni<12; ni++) {
              if(getDisplayIdx(ni, labelOffset, activeMode) === idx) {
                mappedNodeId = ni + 1;
                break;
              }
            }
            const isCurrentlyActive = highlightedNodes.includes(mappedNodeId);

            return (
              <div key={idx} className={`group relative p-0.5 transition-all duration-300 ${isCurrentlyActive ? 'scale-[1.01] md:scale-[1.02]' : ''}`}>
                <div className="flex justify-between items-end mb-1 px-1">
                  <label className="text-[8px] md:text-[9px] text-gray-500 uppercase tracking-widest font-black block">Leaf {idx + 1}</label>
                </div>
                <input 
                  type="text" value={label} onChange={(e) => updateLabel(idx, e.target.value)} placeholder={`Terminal input ${idx + 1}...`}
                  className={`w-full bg-white/5 border rounded-lg md:rounded-xl px-3 py-2 md:px-4 md:py-3 text-xs md:text-sm font-medium focus:bg-cyan-950/10 outline-none transition-all placeholder-gray-800 ${isCurrentlyActive ? 'border-cyan-500/50 text-white' : 'border-white/5 text-cyan-50/70'}`}
                />
              </div>
            );
          })}
        </div>

        <div className="pt-4 md:pt-6 border-t border-white/5 space-y-3 md:space-y-4 shrink-0 pb-6 bg-black/20 -mx-6 md:-mx-8 px-6 md:px-8">
          <div className="flex justify-between items-baseline px-1">
            <h3 className="text-[10px] md:text-xs font-black text-gray-500 uppercase tracking-[0.2em]">Flow of Life</h3>
            <span className="font-mono text-[10px] md:text-[11px] text-cyan-500 px-2 py-0.5 rounded bg-cyan-950/30">Phase: {labelOffset + 1}</span>
          </div>
          <div className="flex p-1 bg-white/5 rounded-xl md:rounded-2xl gap-1">
            <button onClick={() => { setActiveMode('linear'); setIsCycling(false); }} className={`flex-1 py-2 md:py-3 rounded-lg md:rounded-xl text-[9px] md:text-[10px] font-black tracking-widest transition-all ${activeMode === 'linear' ? 'bg-cyan-500 text-black shadow-lg shadow-cyan-500/20' : 'text-gray-400'}`}>LINEAR</button>
            <button onClick={() => { setActiveMode('bifurcation'); setIsCycling(false); }} className={`flex-1 py-2 md:py-3 rounded-lg md:rounded-xl text-[9px] md:text-[10px] font-black tracking-widest transition-all ${activeMode === 'bifurcation' ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-600/20' : 'text-gray-400'}`}>BIFURCATE</button>
          </div>
          <div className="grid grid-cols-2 gap-2 md:gap-3">
            <button onClick={() => handleShift('down')} className="bg-white/5 hover:bg-cyan-500/10 py-3 md:py-4 rounded-xl md:rounded-2xl border border-white/5 text-base md:text-lg font-black tracking-widest transition-all uppercase">-</button>
            <button onClick={() => handleShift('up')} className="bg-white/5 hover:bg-cyan-500/10 py-3 md:py-4 rounded-xl md:rounded-2xl border border-white/5 text-base md:text-lg font-black tracking-widest transition-all uppercase">+</button>
          </div>
          <button onClick={() => setIsCycling(!isCycling)} className={`w-full py-3 md:py-4 rounded-xl md:rounded-2xl border font-black text-[10px] md:text-[11px] tracking-[0.2em] transition-all uppercase ${isCycling ? 'bg-red-600 text-white shadow-xl' : 'bg-cyan-600/10 text-cyan-400 border-cyan-500/20 hover:border-cyan-500/50'}`}>
            {isCycling ? 'Stop Stream' : `Animate Stream`}
          </button>
        </div>
      </aside>

      <div className="flex-1 h-[50vh] md:h-[70vh] lg:h-full flex items-center justify-center p-2 md:p-4 lg:p-12">
        <div className="w-full h-full max-w-5xl max-h-[85vh] flex items-center justify-center">
          {renderDiagram()}
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(6, 182, 212, 0.15); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(6, 182, 212, 0.3); }
      `}</style>
    </div>
  );
};

export default TreeOfLifeMode;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { KATHARA_GRID_NODES, KATHARA_GRID_LINES, KATHARA_CLOCK_POINTS, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, MUQATTAT_LETTERS } from '../constants.ts';
import { getSliceAtPoint } from '../utils.ts';

interface TreeOfLifeModeProps {
  rotation: number;
  onClose: () => void;
}

const PRESET_1 = [
  "Book", "Chosen One | Rasul", "Sign", "Prophet", "Challenge | Rescue", "Curse", 
  "Blessed Land", "Believer | Servant", "Suhuf", "Teacher", "Witness | Driver", "Stone"
];

const PRESET_2 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Heifer",
  "Stone",
  "Boat | Bee",
  "Noah | Musa",
  "Idris | Isa",
  "Tree | Mountain",
  "Amanah",
  "Return",
  "Solomon | Dawud",
  "Book | Yahya"
];

const PRESET_3 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Rushd",
  "Stone",
  "Iron | Wood",
  "Noah | Musa",
  "Idris | Isa",
  "Iron | Mountain",
  "Amanah",
  "Dawud",
  "Solomon | Death",
  "Book | Yahya"
];

interface BifurcationStage {
  main: number[];
  manualLines: [number, number][];
  isBlackPhase?: boolean;
}

const TreeOfLifeMode: React.FC<TreeOfLifeModeProps> = ({ rotation, onClose }) => {
  const [labels, setLabels] = useState<string[]>(Array(12).fill(''));
  const [labelOffset, setLabelOffset] = useState(0); 
  const [isCycling, setIsCycling] = useState(false);
  const [activeMode, setActiveMode] = useState<'linear' | 'bifurcation'>('linear');
  const [highlightedNodes, setHighlightedNodes] = useState<number[]>([]);

  const [showLightning, setShowLightning] = useState(false);
  const [showExplosion, setShowExplosion] = useState(false);

  // Domain Node Sets
  const BLUE_NODES = [1, 2, 3, 4, 5, 6, 13];
  const GREEN_NODES = [12, 11, 10, 9, 8, 7, 15];

  const LOOP_LINES: [number, number][] = [[2, 3], [3, 6], [6, 9], [9, 11], [11, 10], [10, 7], [7, 4], [4, 2]];
  const BOLT_3_10_LINES: [number, number][] = [[3, 13], [4, 13], [4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9], [9, 15], [10, 15]];
  const BOLT_4_9_LINES: [number, number][] = [[4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9]];
  const PATH_5_8_LINES: [number, number][] = [[5, 6], [6, 14], [7, 14], [7, 8]];
  const CROSS_PLUS_LINES: [number, number][] = [[6, 14], [7, 14], [5, 14], [14, 8], [6, 7], [5, 8]];

  const DUAL_GROUP_LINES: [number, number][] = [
    [1, 2], [2, 3], [2, 4], [2, 13], [3, 13], [4, 13], [3, 5], [4, 5], [5, 6], [3, 6], [13, 5],
    [12, 11], [11, 10], [11, 9], [9, 15], [10, 15], [15, 8], [8, 9], [8, 10], [7, 8], [7, 10], [15, 11]
  ];
  const SQUARE_PLUS_LINES: [number, number][] = [[5, 6], [5, 7], [6, 8], [7, 8], [6, 14], [14, 7], [5, 14], [14, 8]];

  const BIFURCATION_STAGES: BifurcationStage[] = useMemo(() => [
    { main: [1, 12], manualLines: [], isBlackPhase: true },
    { main: [2, 11], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: CROSS_PLUS_LINES },
    { main: [12, 1], manualLines: DUAL_GROUP_LINES },
    { main: [11, 2], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: SQUARE_PLUS_LINES },
  ], []);

  const handleSyncFromWheel = (mode: 'full' | 'title') => {
    const newLabels = KATHARA_CLOCK_POINTS.map(pointValue => {
        const slice = getSliceAtPoint(pointValue, rotation);
        const chapterInfo = CHAPTER_DETAILS.find(c => c.number === slice.id);
        const title = chapterInfo?.englishName || 'Unknown';
        const letters = MUQATTAT_LETTERS.get(slice.id)?.join(' ') || '';
        if (mode === 'title') return `${title}${letters ? ` | ${letters}` : ''}`;
        return `${slice.id} ${title}${letters ? ` | ${letters}` : ''}`;
    });
    setLabels(newLabels);
    setLabelOffset(0);
  };

  const handlePreset = (num: number) => {
    setLabelOffset(0);
    setHighlightedNodes([]);
    setIsCycling(false);
    if (num === 0) setLabels(Array(12).fill(''));
    else if (num === 1) setLabels([...PRESET_1]);
    else if (num === 2) setLabels([...PRESET_2]);
    else if (num === 3) setLabels([...PRESET_3]);
  };

  const updateVisuals = useCallback((offset: number) => {
    if (activeMode === 'linear') setHighlightedNodes([offset + 1]);
    else setHighlightedNodes(BIFURCATION_STAGES[offset].main);
  }, [activeMode, BIFURCATION_STAGES]);

  const handleShift = useCallback((direction: 'up' | 'down') => {
    setLabelOffset((prev) => {
      const next = direction === 'up' ? (prev + 1) % 12 : (prev - 1 + 12) % 12;
      if (activeMode === 'bifurcation') {
        if (prev === 11 && next === 0) { setShowLightning(true); setTimeout(() => setShowLightning(false), 800); }
        if (prev === 5 && next === 6) { setShowExplosion(true); setTimeout(() => setShowExplosion(false), 1200); }
      }
      updateVisuals(next);
      return next;
    });
  }, [updateVisuals, activeMode]);

  useEffect(() => { updateVisuals(labelOffset); }, [activeMode, updateVisuals, labelOffset]);

  useEffect(() => {
    if (!isCycling) return;
    const intervalId = window.setInterval(() => { handleShift('up'); }, 1800);
    return () => clearInterval(intervalId);
  }, [isCycling, handleShift]);

  const updateLabel = (index: number, val: string) => {
    const next = [...labels];
    next[index] = val;
    setLabels(next);
  };

  const getLineStatus = useCallback((from: number, to: number, h: number[], offset: number) => {
    if (activeMode === 'linear') {
      const nodeId = h[0];
      return from === nodeId || to === nodeId ? 'main' : null;
    }
    const stage = BIFURCATION_STAGES[offset];
    if (stage.isBlackPhase) return 'black';
    const isManual = stage.manualLines?.some(l => (l[0] === from && l[1] === to) || (l[0] === to && l[1] === from));
    return isManual ? 'main' : null;
  }, [activeMode, BIFURCATION_STAGES]);

  const getDisplayIdx = useCallback((nodeIdx: number, offset: number, mode: 'linear' | 'bifurcation') => {
    if (mode === 'linear') return (nodeIdx - offset + 12) % 12;
    const step = offset % 6;
    const hasCrossed = offset >= 6;
    if (nodeIdx < 6) return hasCrossed ? (nodeIdx - step + 6) % 6 + 6 : (nodeIdx - step + 6) % 6;
    return hasCrossed ? (11 - nodeIdx - step + 6) % 6 : (11 - nodeIdx - step + 6) % 6 + 6;
  }, []);

  const renderDiagram = () => {
    const isPhase2or8 = activeMode === 'bifurcation' && (labelOffset === 1 || labelOffset === 7);
    const extraSilverLines = isPhase2or8 ? [[9, 7], [6, 4]] : [];

    return (
      <div className="relative flex items-center justify-center bg-black/80 overflow-hidden h-full w-full rounded-2xl lg:rounded-none">
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[100%] h-[100%] rounded-full bg-cyan-950/10 blur-[80px] lg:blur-[180px]"></div>
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000_100%)] opacity-80"></div>
        </div>

        <style>{`
          .node-glow { filter: drop-shadow(0 0 15px currentColor); }
          .kathara-svg { width: 100%; height: 100%; max-height: 85vh; }
          .junction-box { stroke-width: 1; fill: rgba(0, 0, 0, 0.85); stroke: rgba(255, 255, 255, 0.1); }
          .active-junction { stroke: #fff; stroke-width: 1.5; fill: rgba(8, 145, 178, 0.3); }
          .filter-junction { stroke: #06b6d4; fill: rgba(0, 30, 40, 0.9); }

          @keyframes flow-up { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }
          @keyframes flow-down { 0% { stroke-dashoffset: 0; } 100% { stroke-dashoffset: 40; } }
          @keyframes flow-silver { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }

          .liquid-blue-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-up 1.6s linear infinite; filter: drop-shadow(0 0 6px #06b6d4); }
          .liquid-green-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-down 1.6s linear infinite; filter: drop-shadow(0 0 6px #4ade80); }
          .liquid-silver-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-silver 1.6s linear infinite; filter: drop-shadow(0 0 6px #cbd5e1); }

          @keyframes spark { 0%, 100% { opacity: 0; stroke-width: 1; } 20% { opacity: 1; stroke-width: 4; } 60% { opacity: 1; stroke-width: 2; } }
          .lightning-bolt { stroke: #fff; filter: drop-shadow(0 0 12px cyan); animation: spark 0.25s infinite; }

          @keyframes blast { 0% { transform: scale(0); opacity: 1; filter: blur(0px); } 50% { transform: scale(3); opacity: 0.5; filter: blur(5px); } 100% { transform: scale(4.5); opacity: 0; filter: blur(10px); } }
          .fire-burst { fill: #f97316; animation: blast 0.8s ease-out forwards; }
        `}</style>

        <svg viewBox="-70 0 290 280" className="kathara-svg drop-shadow-[0_0_80px_rgba(6,182,212,0.15)]">
          <defs>
            <linearGradient id="activeGrad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#0891b2" />
              <stop offset="100%" stopColor="#06b6d4" />
            </linearGradient>
          </defs>

          <g>
            {KATHARA_GRID_LINES.map((line, index) => {
              const fromNode = KATHARA_GRID_NODES.find(n => n.id === line.from);
              const toNode = KATHARA_GRID_NODES.find(n => n.id === line.to);
              if (!fromNode || !toNode) return null;

              const status = getLineStatus(line.from, line.to, highlightedNodes, labelOffset);
              const isMain = status === 'main';
              const isAscending = fromNode.y > toNode.y;

              const isBlueDomain = (BLUE_NODES.includes(line.from) && BLUE_NODES.includes(line.to)) || 
                                  ((line.from === 14 || line.to === 14) && (BLUE_NODES.includes(line.from) || BLUE_NODES.includes(line.to)));

              const isGreenDomain = (GREEN_NODES.includes(line.from) && GREEN_NODES.includes(line.to)) || 
                                   ((line.from === 14 || line.to === 14) && (GREEN_NODES.includes(line.from) || GREEN_NODES.includes(line.to)));

              const isPhase12 = activeMode === 'bifurcation' && labelOffset === 11;
              const isSilverLine = isPhase12 && (
                (line.from === 6 && line.to === 8) || (line.from === 8 && line.to === 6) ||
                (line.from === 8 && line.to === 7) || (line.from === 7 && line.to === 8) ||
                (line.from === 7 && line.to === 5) || (line.from === 5 && line.to === 7) ||
                (line.from === 5 && line.to === 6) || (line.from === 6 && line.to === 5)
              );

              const showBlue = activeMode === 'linear' ? isMain : (isMain && isBlueDomain && !isSilverLine);
              const showGreen = activeMode === 'linear' ? isMain : (isMain && isGreenDomain && !isSilverLine);
              const showSilver = isMain && isSilverLine;

              const dx = toNode.x - fromNode.x;
              const dy = toNode.y - fromNode.y;
              const len = Math.sqrt(dx*dx + dy*dy);
              const nx = -dy / (len || 1);
              const ny = dx / (len || 1);
              const offsetDist = activeMode === 'linear' ? 2.0 : 0;

              return (
                <g key={index}>
                  <line 
                    x1={fromNode.x} y1={fromNode.y} 
                    x2={toNode.x} y2={toNode.y} 
                    stroke={isMain ? (isSilverLine ? "rgba(203,213,225,0.2)" : "rgba(255,255,255,0.12)") : status === 'black' ? "#0a0a0a" : "rgba(255,255,255,0.04)"}
                    strokeWidth={isMain ? 4 : 1}
                    className="transition-all duration-700"
                  />
                  {showBlue && <line x1={(isAscending ? fromNode.x : toNode.x) + nx * offsetDist} y1={(isAscending ? fromNode.y : toNode.y) + ny * offsetDist} x2={(isAscending ? toNode.x : fromNode.x) + nx * offsetDist} y2={(isAscending ? toNode.y : fromNode.y) + ny * offsetDist} stroke="#06b6d4" strokeWidth="3.5" className="liquid-blue-flow" />}
                  {showGreen && <line x1={(isAscending ? toNode.x : fromNode.x) - nx * offsetDist} y1={(isAscending ? toNode.y : fromNode.y) - ny * offsetDist} x2={(isAscending ? fromNode.x : toNode.x) - nx * offsetDist} y2={(isAscending ? fromNode.y : toNode.y) - ny * offsetDist} stroke="#4ade80" strokeWidth="3.5" className="liquid-green-flow" />}
                  {showSilver && <line x1={fromNode.x} y1={fromNode.y} x2={toNode.x} y2={toNode.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />}
                </g>
              );
            })}
            {extraSilverLines.map(([fromId, toId], idx) => {
              const f = KATHARA_GRID_NODES.find(n => n.id === fromId);
              const t = KATHARA_GRID_NODES.find(n => n.id === toId);
              if (!f || !t) return null;
              return (
                <g key={`extra-silver-${idx}`}>
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="rgba(203,213,225,0.4)" strokeWidth="3" />
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />
                </g>
              );
            })}
          </g>

          {showLightning && (
            <g className="pointer-events-none">
              <path d="M 75 20 L 95 60 L 55 100 L 75 140" fill="none" className="lightning-bolt" />
              <path d="M 30 140 L 55 170 L 35 200 L 75 240" fill="none" className="lightning-bolt" />
              <path d="M 120 140 L 95 170 L 115 200 L 75 240" fill="none" className="lightning-bolt" />
            </g>
          )}

          {showExplosion && (
            <g transform="translate(75, 140)" className="pointer-events-none">
              <circle r="12" className="fire-burst" />
              <circle r="8" className="fire-burst" style={{ animationDelay: '0.1s' }} />
            </g>
          )}

          {KATHARA_GRID_NODES.map((node, nodeIdx) => {
            const isFilter = node.id > 12;
            const isHighlighted = highlightedNodes.includes(node.id);
            const displayLabelIdx = isFilter ? -1 : getDisplayIdx(nodeIdx, labelOffset, activeMode);
            const rawLabel = isFilter ? '' : labels[displayLabelIdx];

            const filterFullLabel = node.id === 13 ? '△108⚡' : node.id === 14 ? '🔥103🐟' : node.id === 15 ? '⚫110🌳' : null;

            const labelParts = rawLabel ? rawLabel.split('|').map(p => p.trim()) : [];
            const hasMultiple = labelParts.length > 1;
            const isSpineNode = node.x === 75 && node.id <= 12; 
            const isLeftSide = node.x < 75;

            return (
              <g key={node.id} className="transition-all duration-500">
                {isFilter ? (
                  <g>
                    {isHighlighted && <rect x={node.x-28} y={node.y-12} width="56" height="24" rx="4" fill="rgba(6,182,212,0.15)" className="animate-pulse" />}
                    <rect x={node.x-25} y={node.y-10} width="50" height="20" rx="3" className={`filter-junction ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#06b6d4' }} />
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#0891b2"} className="font-mono tracking-tighter" style={{ pointerEvents: 'none' }}>
                      {filterFullLabel}
                    </text>
                  </g>
                ) : (
                  <g>
                    <rect x={node.x-14} y={node.y-14} width="28" height="28" rx="6" className={`junction-box ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#fff' }} />
                    {isHighlighted && <circle cx={node.x} cy={node.y} r={22} fill="url(#activeGrad)" opacity="0.1" className="animate-pulse" />}
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="8" fontWeight="black" fill={isHighlighted ? "#fff" : "#555"}>{node.id}</text>
                    {rawLabel && (
                      <g className="pointer-events-none">
                         {isSpineNode && hasMultiple ? (
                          <>
                            <rect x={node.x - 76} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x - 22} y={node.y} textAnchor="end" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[0]}</text>
                            <rect x={node.x + 18} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x + 22} y={node.y} textAnchor="start" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[1]}</text>
                          </>
                         ) : (
                          <g>
                             <rect x={isLeftSide ? node.x - 76 : node.x + 18} y={node.y - (hasMultiple ? 14 : 9)} width="58" height={hasMultiple ? 28 : 18} rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                             <text x={isLeftSide ? node.x - 22 : node.x + 22} y={node.y} textAnchor={isLeftSide ? "end" : "start"} dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">
                               {hasMultiple ? (<><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="-0.5em">{labelParts[0]}</tspan><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="1.1em">{labelParts[1]}</tspan></>) : rawLabel}
                             </text>
                          </g>
                         )}
                      </g>
                    )}
                  </g>
                )}
              </g>
            );
          })}
        </svg>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#02040a] animate-in fade-in zoom-in duration-500 overflow-y-auto custom-scrollbar">
      <aside className="w-full lg:w-[420px] p-6 lg:p-8 border-b lg:border-r border-white/10 flex flex-col space-y-4 md:space-y-6 bg-black/40 backdrop-blur-xl shrink-0">
        <div className="flex justify-between items-start shrink-0">
          <div className="space-y-1">
            <h2 className="text-xl md:text-2xl font-black text-white tracking-tighter uppercase italic leading-tight">
              Photosynthesis:
              <span className="block text-[10px] md:text-sm font-bold tracking-widest text-cyan-400 mt-1 not-italic">
                Harvesting Love and Intelligence in Form
              </span>
            </h2>
            <div className="flex flex-wrap gap-1.5 mt-2">
               {[0, 1, 2, 3].map(n => (
                 <button key={n} onClick={() => handlePreset(n)} className={`w-8 h-8 md:w-9 md:h-9 rounded-lg border font-black text-[9px] md:text-[10px] transition-all ${n === 0 ? 'bg-white/5 border-white/10 text-gray-500' : 'bg-cyan-950/20 border-cyan-500/30 text-cyan-400 hover:bg-cyan-500 hover:text-black'}`}>
                   {n === 0 ? 'CLR' : `P${n}`}
                 </button>
               ))}
               <button onClick={() => handleSyncFromWheel('full')} className="px-2 md:px-3 h-8 md:h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[9px] md:text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 1</button>
               <button onClick={() => handleSyncFromWheel('title')} className="px-2 md:px-3 h-8 md:h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[9px] md:text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 2</button>
            </div>
          </div>
          <button onClick={onClose} className="p-2 md:p-3 rounded-2xl bg-white/5 text-gray-400 hover:text-white transition-all hover:bg-white/10 shrink-0">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 md:h-6 md:w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="space-y-3 md:space-y-4">
          {labels.map((label, idx) => {
            let mappedNodeId = -1;
            for(let ni=0; ni<12; ni++) {
              if(getDisplayIdx(ni, labelOffset, activeMode) === idx) {
                mappedNodeId = ni + 1;
                break;
              }
            }
            const isCurrentlyActive = highlightedNodes.includes(mappedNodeId);

            return (
              <div key={idx} className={`group relative p-0.5 transition-all duration-300 ${isCurrentlyActive ? 'scale-[1.01] md:scale-[1.02]' : ''}`}>
                <div className="flex justify-between items-end mb-1 px-1">
                  <label className="text-[8px] md:text-[9px] text-gray-500 uppercase tracking-widest font-black block">Leaf {idx + 1}</label>
                </div>
                <input 
                  type="text" value={label} onChange={(e) => updateLabel(idx, e.target.value)} placeholder={`Terminal input ${idx + 1}...`}
                  className={`w-full bg-white/5 border rounded-lg md:rounded-xl px-3 py-2 md:px-4 md:py-3 text-xs md:text-sm font-medium focus:bg-cyan-950/10 outline-none transition-all placeholder-gray-800 ${isCurrentlyActive ? 'border-cyan-500/50 text-white' : 'border-white/5 text-cyan-50/70'}`}
                />
              </div>
            );
          })}
        </div>

        <div className="pt-4 md:pt-6 border-t border-white/5 space-y-3 md:space-y-4 shrink-0 pb-6 bg-black/20 -mx-6 md:-mx-8 px-6 md:px-8">
          <div className="flex justify-between items-baseline px-1">
            <h3 className="text-[10px] md:text-xs font-black text-gray-500 uppercase tracking-[0.2em]">Flow of Life</h3>
            <span className="font-mono text-[10px] md:text-[11px] text-cyan-500 px-2 py-0.5 rounded bg-cyan-950/30">Phase: {labelOffset + 1}</span>
          </div>
          <div className="flex p-1 bg-white/5 rounded-xl md:rounded-2xl gap-1">
            <button onClick={() => { setActiveMode('linear'); setIsCycling(false); }} className={`flex-1 py-2 md:py-3 rounded-lg md:rounded-xl text-[9px] md:text-[10px] font-black tracking-widest transition-all ${activeMode === 'linear' ? 'bg-cyan-500 text-black shadow-lg shadow-cyan-500/20' : 'text-gray-400'}`}>LINEAR</button>
            <button onClick={() => { setActiveMode('bifurcation'); setIsCycling(false); }} className={`flex-1 py-2 md:py-3 rounded-lg md:rounded-xl text-[9px] md:text-[10px] font-black tracking-widest transition-all ${activeMode === 'bifurcation' ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-600/20' : 'text-gray-400'}`}>BIFURCATE</button>
          </div>
          <div className="grid grid-cols-2 gap-2 md:gap-3">
            <button onClick={() => handleShift('down')} className="bg-white/5 hover:bg-cyan-500/10 py-3 md:py-4 rounded-xl md:rounded-2xl border border-white/5 text-base md:text-lg font-black tracking-widest transition-all uppercase">-</button>
            <button onClick={() => handleShift('up')} className="bg-white/5 hover:bg-cyan-500/10 py-3 md:py-4 rounded-xl md:rounded-2xl border border-white/5 text-base md:text-lg font-black tracking-widest transition-all uppercase">+</button>
          </div>
          <button onClick={() => setIsCycling(!isCycling)} className={`w-full py-3 md:py-4 rounded-xl md:rounded-2xl border font-black text-[10px] md:text-[11px] tracking-[0.2em] transition-all uppercase ${isCycling ? 'bg-red-600 text-white shadow-xl' : 'bg-cyan-600/10 text-cyan-400 border-cyan-500/20 hover:border-cyan-500/50'}`}>
            {isCycling ? 'Stop Stream' : `Animate Stream`}
          </button>
        </div>
      </aside>

      <div className="flex-1 w-full flex items-center justify-center p-0 lg:p-12 mb-10 lg:mb-0">
        <div className="w-full h-[80vh] md:h-[90vh] lg:h-full flex items-center justify-center">
          {renderDiagram()}
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(6, 182, 212, 0.15); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(6, 182, 212, 0.3); }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default TreeOfLifeMode;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { KATHARA_GRID_NODES, KATHARA_GRID_LINES, KATHARA_CLOCK_POINTS, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, MUQATTAT_LETTERS } from '../constants.ts';
import { getSliceAtPoint } from '../utils.ts';

interface TreeOfLifeModeProps {
  rotation: number;
  onClose: () => void;
}

const PRESET_1 = [
  "Book", "Chosen One | Rasul", "Sign", "Prophet", "Challenge | Rescue", "Curse", 
  "Blessed Land", "Believer | Servant", "Suhuf", "Teacher", "Witness | Driver", "Stone"
];

const PRESET_2 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Heifer",
  "Stone",
  "Boat | Bee",
  "Noah | Musa",
  "Idris | Isa",
  "Tree | Mountain",
  "Amanah",
  "Return",
  "Solomon | Dawud",
  "Book | Yahya"
];

const PRESET_3 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Rushd",
  "Stone",
  "Iron | Wood",
  "Noah | Musa",
  "Idris | Isa",
  "Iron | Mountain",
  "Amanah",
  "Dawud",
  "Solomon | Death",
  "Book | Yahya"
];

interface BifurcationStage {
  main: number[];
  manualLines: [number, number][];
  isBlackPhase?: boolean;
}

const TreeOfLifeMode: React.FC<TreeOfLifeModeProps> = ({ rotation, onClose }) => {
  const [labels, setLabels] = useState<string[]>(Array(12).fill(''));
  const [labelOffset, setLabelOffset] = useState(0); 
  const [isCycling, setIsCycling] = useState(false);
  const [activeMode, setActiveMode] = useState<'linear' | 'bifurcation'>('linear');
  const [highlightedNodes, setHighlightedNodes] = useState<number[]>([]);

  const [showLightning, setShowLightning] = useState(false);
  const [showExplosion, setShowExplosion] = useState(false);

  // Domain Node Sets
  const BLUE_NODES = [1, 2, 3, 4, 5, 6, 13];
  const GREEN_NODES = [12, 11, 10, 9, 8, 7, 15];

  const LOOP_LINES: [number, number][] = [[2, 3], [3, 6], [6, 9], [9, 11], [11, 10], [10, 7], [7, 4], [4, 2]];
  const BOLT_3_10_LINES: [number, number][] = [[3, 13], [4, 13], [4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9], [9, 15], [10, 15]];
  const BOLT_4_9_LINES: [number, number][] = [[4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9]];
  const PATH_5_8_LINES: [number, number][] = [[5, 6], [6, 14], [7, 14], [7, 8]];
  const CROSS_PLUS_LINES: [number, number][] = [[6, 14], [7, 14], [5, 14], [14, 8], [6, 7], [5, 8]];

  const DUAL_GROUP_LINES: [number, number][] = [
    [1, 2], [2, 3], [2, 4], [2, 13], [3, 13], [4, 13], [3, 5], [4, 5], [5, 6], [3, 6], [13, 5],
    [12, 11], [11, 10], [11, 9], [9, 15], [10, 15], [15, 8], [8, 9], [8, 10], [7, 8], [7, 10], [15, 11]
  ];
  const SQUARE_PLUS_LINES: [number, number][] = [[5, 6], [5, 7], [6, 8], [7, 8], [6, 14], [14, 7], [5, 14], [14, 8]];

  const BIFURCATION_STAGES: BifurcationStage[] = useMemo(() => [
    { main: [1, 12], manualLines: [], isBlackPhase: true },
    { main: [2, 11], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: CROSS_PLUS_LINES },
    { main: [12, 1], manualLines: DUAL_GROUP_LINES },
    { main: [11, 2], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: SQUARE_PLUS_LINES },
  ], []);

  const handleSyncFromWheel = (mode: 'full' | 'title') => {
    const newLabels = KATHARA_CLOCK_POINTS.map(pointValue => {
        const slice = getSliceAtPoint(pointValue, rotation);
        const chapterInfo = CHAPTER_DETAILS.find(c => c.number === slice.id);
        const title = chapterInfo?.englishName || 'Unknown';
        const letters = MUQATTAT_LETTERS.get(slice.id)?.join(' ') || '';
        if (mode === 'title') return `${title}${letters ? ` | ${letters}` : ''}`;
        return `${slice.id} ${title}${letters ? ` | ${letters}` : ''}`;
    });
    setLabels(newLabels);
    setLabelOffset(0);
  };

  const handlePreset = (num: number) => {
    setLabelOffset(0);
    setHighlightedNodes([]);
    setIsCycling(false);
    if (num === 0) setLabels(Array(12).fill(''));
    else if (num === 1) setLabels([...PRESET_1]);
    else if (num === 2) setLabels([...PRESET_2]);
    else if (num === 3) setLabels([...PRESET_3]);
  };

  const updateVisuals = useCallback((offset: number) => {
    if (activeMode === 'linear') setHighlightedNodes([offset + 1]);
    else setHighlightedNodes(BIFURCATION_STAGES[offset].main);
  }, [activeMode, BIFURCATION_STAGES]);

  const handleShift = useCallback((direction: 'up' | 'down') => {
    setLabelOffset((prev) => {
      const next = direction === 'up' ? (prev + 1) % 12 : (prev - 1 + 12) % 12;
      if (activeMode === 'bifurcation') {
        if (prev === 11 && next === 0) { setShowLightning(true); setTimeout(() => setShowLightning(false), 800); }
        if (prev === 5 && next === 6) { setShowExplosion(true); setTimeout(() => setShowExplosion(false), 1200); }
      }
      updateVisuals(next);
      return next;
    });
  }, [updateVisuals, activeMode]);

  useEffect(() => { updateVisuals(labelOffset); }, [activeMode, updateVisuals, labelOffset]);

  useEffect(() => {
    if (!isCycling) return;
    const intervalId = window.setInterval(() => { handleShift('up'); }, 1800);
    return () => clearInterval(intervalId);
  }, [isCycling, handleShift]);

  const updateLabel = (index: number, val: string) => {
    const next = [...labels];
    next[index] = val;
    setLabels(next);
  };

  const getLineStatus = useCallback((from: number, to: number, h: number[], offset: number) => {
    if (activeMode === 'linear') {
      const nodeId = h[0];
      return from === nodeId || to === nodeId ? 'main' : null;
    }
    const stage = BIFURCATION_STAGES[offset];
    if (stage.isBlackPhase) return 'black';
    const isManual = stage.manualLines?.some(l => (l[0] === from && l[1] === to) || (l[0] === to && l[1] === from));
    return isManual ? 'main' : null;
  }, [activeMode, BIFURCATION_STAGES]);

  const getDisplayIdx = useCallback((nodeIdx: number, offset: number, mode: 'linear' | 'bifurcation') => {
    if (mode === 'linear') return (nodeIdx - offset + 12) % 12;
    const step = offset % 6;
    const hasCrossed = offset >= 6;
    if (nodeIdx < 6) return hasCrossed ? (nodeIdx - step + 6) % 6 + 6 : (nodeIdx - step + 6) % 6;
    return hasCrossed ? (11 - nodeIdx - step + 6) % 6 : (11 - nodeIdx - step + 6) % 6 + 6;
  }, []);

  const renderDiagram = () => {
    const isPhase2or8 = activeMode === 'bifurcation' && (labelOffset === 1 || labelOffset === 7);
    const extraSilverLines = isPhase2or8 ? [[9, 7], [6, 4]] : [];

    return (
      <div className="relative flex items-center justify-center bg-black/80 overflow-hidden h-full w-full rounded-2xl lg:rounded-none">
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[100%] h-[100%] rounded-full bg-cyan-950/10 blur-[80px] lg:blur-[180px]"></div>
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000_100%)] opacity-80"></div>
        </div>

        <style>{`
          .node-glow { filter: drop-shadow(0 0 15px currentColor); }
          .kathara-svg { width: 100%; height: auto; display: block; }
          .junction-box { stroke-width: 1; fill: rgba(0, 0, 0, 0.85); stroke: rgba(255, 255, 255, 0.1); }
          .active-junction { stroke: #fff; stroke-width: 1.5; fill: rgba(8, 145, 178, 0.3); }
          .filter-junction { stroke: #06b6d4; fill: rgba(0, 30, 40, 0.9); }

          @keyframes flow-up { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }
          @keyframes flow-down { 0% { stroke-dashoffset: 0; } 100% { stroke-dashoffset: 40; } }
          @keyframes flow-silver { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }

          .liquid-blue-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-up 1.6s linear infinite; filter: drop-shadow(0 0 6px #06b6d4); }
          .liquid-green-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-down 1.6s linear infinite; filter: drop-shadow(0 0 6px #4ade80); }
          .liquid-silver-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-silver 1.6s linear infinite; filter: drop-shadow(0 0 6px #cbd5e1); }

          @keyframes spark { 0%, 100% { opacity: 0; stroke-width: 1; } 20% { opacity: 1; stroke-width: 4; } 60% { opacity: 1; stroke-width: 2; } }
          .lightning-bolt { stroke: #fff; filter: drop-shadow(0 0 12px cyan); animation: spark 0.25s infinite; }

          @keyframes blast { 0% { transform: scale(0); opacity: 1; filter: blur(0px); } 50% { transform: scale(3); opacity: 0.5; filter: blur(5px); } 100% { transform: scale(4.5); opacity: 0; filter: blur(10px); } }
          .fire-burst { fill: #f97316; animation: blast 0.8s ease-out forwards; }
        `}</style>

        <svg viewBox="-70 0 290 280" className="kathara-svg drop-shadow-[0_0_80px_rgba(6,182,212,0.15)]">
          <defs>
            <linearGradient id="activeGrad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#0891b2" />
              <stop offset="100%" stopColor="#06b6d4" />
            </linearGradient>
          </defs>

          <g>
            {KATHARA_GRID_LINES.map((line, index) => {
              const fromNode = KATHARA_GRID_NODES.find(n => n.id === line.from);
              const toNode = KATHARA_GRID_NODES.find(n => n.id === line.to);
              if (!fromNode || !toNode) return null;

              const status = getLineStatus(line.from, line.to, highlightedNodes, labelOffset);
              const isMain = status === 'main';
              const isAscending = fromNode.y > toNode.y;

              const isBlueDomain = (BLUE_NODES.includes(line.from) && BLUE_NODES.includes(line.to)) || 
                                  ((line.from === 14 || line.to === 14) && (BLUE_NODES.includes(line.from) || BLUE_NODES.includes(line.to)));

              const isGreenDomain = (GREEN_NODES.includes(line.from) && GREEN_NODES.includes(line.to)) || 
                                   ((line.from === 14 || line.to === 14) && (GREEN_NODES.includes(line.from) || GREEN_NODES.includes(line.to)));

              const isPhase12 = activeMode === 'bifurcation' && labelOffset === 11;
              const isSilverLine = isPhase12 && (
                (line.from === 6 && line.to === 8) || (line.from === 8 && line.to === 6) ||
                (line.from === 8 && line.to === 7) || (line.from === 7 && line.to === 8) ||
                (line.from === 7 && line.to === 5) || (line.from === 5 && line.to === 7) ||
                (line.from === 5 && line.to === 6) || (line.from === 6 && line.to === 5)
              );

              const showBlue = activeMode === 'linear' ? isMain : (isMain && isBlueDomain && !isSilverLine);
              const showGreen = activeMode === 'linear' ? isMain : (isMain && isGreenDomain && !isSilverLine);
              const showSilver = isMain && isSilverLine;

              const dx = toNode.x - fromNode.x;
              const dy = toNode.y - fromNode.y;
              const len = Math.sqrt(dx*dx + dy*dy);
              const nx = -dy / (len || 1);
              const ny = dx / (len || 1);
              const offsetDist = activeMode === 'linear' ? 2.0 : 0;

              return (
                <g key={index}>
                  <line 
                    x1={fromNode.x} y1={fromNode.y} 
                    x2={toNode.x} y2={toNode.y} 
                    stroke={isMain ? (isSilverLine ? "rgba(203,213,225,0.2)" : "rgba(255,255,255,0.12)") : status === 'black' ? "#0a0a0a" : "rgba(255,255,255,0.04)"}
                    strokeWidth={isMain ? 4 : 1}
                    className="transition-all duration-700"
                  />
                  {showBlue && <line x1={(isAscending ? fromNode.x : toNode.x) + nx * offsetDist} y1={(isAscending ? fromNode.y : toNode.y) + ny * offsetDist} x2={(isAscending ? toNode.x : fromNode.x) + nx * offsetDist} y2={(isAscending ? toNode.y : fromNode.y) + ny * offsetDist} stroke="#06b6d4" strokeWidth="3.5" className="liquid-blue-flow" />}
                  {showGreen && <line x1={(isAscending ? toNode.x : fromNode.x) - nx * offsetDist} y1={(isAscending ? toNode.y : fromNode.y) - ny * offsetDist} x2={(isAscending ? fromNode.x : toNode.x) - nx * offsetDist} y2={(isAscending ? fromNode.y : toNode.y) - ny * offsetDist} stroke="#4ade80" strokeWidth="3.5" className="liquid-green-flow" />}
                  {showSilver && <line x1={fromNode.x} y1={fromNode.y} x2={toNode.x} y2={toNode.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />}
                </g>
              );
            })}
            {extraSilverLines.map(([fromId, toId], idx) => {
              const f = KATHARA_GRID_NODES.find(n => n.id === fromId);
              const t = KATHARA_GRID_NODES.find(n => n.id === toId);
              if (!f || !t) return null;
              return (
                <g key={`extra-silver-${idx}`}>
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="rgba(203,213,225,0.4)" strokeWidth="3" />
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />
                </g>
              );
            })}
          </g>

          {showLightning && (
            <g className="pointer-events-none">
              <path d="M 75 20 L 95 60 L 55 100 L 75 140" fill="none" className="lightning-bolt" />
              <path d="M 30 140 L 55 170 L 35 200 L 75 240" fill="none" className="lightning-bolt" />
              <path d="M 120 140 L 95 170 L 115 200 L 75 240" fill="none" className="lightning-bolt" />
            </g>
          )}

          {showExplosion && (
            <g transform="translate(75, 140)" className="pointer-events-none">
              <circle r="12" className="fire-burst" />
              <circle r="8" className="fire-burst" style={{ animationDelay: '0.1s' }} />
            </g>
          )}

          {KATHARA_GRID_NODES.map((node, nodeIdx) => {
            const isFilter = node.id > 12;
            const isHighlighted = highlightedNodes.includes(node.id);
            const displayLabelIdx = isFilter ? -1 : getDisplayIdx(nodeIdx, labelOffset, activeMode);
            const rawLabel = isFilter ? '' : labels[displayLabelIdx];

            const filterFullLabel = node.id === 13 ? '△108⚡' : node.id === 14 ? '🔥103🐟' : node.id === 15 ? '⚫110🌳' : null;

            const labelParts = rawLabel ? rawLabel.split('|').map(p => p.trim()) : [];
            const hasMultiple = labelParts.length > 1;
            const isSpineNode = node.x === 75 && node.id <= 12; 
            const isLeftSide = node.x < 75;

            return (
              <g key={node.id} className="transition-all duration-500">
                {isFilter ? (
                  <g>
                    {isHighlighted && <rect x={node.x-28} y={node.y-12} width="56" height="24" rx="4" fill="rgba(6,182,212,0.15)" className="animate-pulse" />}
                    <rect x={node.x-25} y={node.y-10} width="50" height="20" rx="3" className={`filter-junction ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#06b6d4' }} />
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#0891b2"} className="font-mono tracking-tighter" style={{ pointerEvents: 'none' }}>
                      {filterFullLabel}
                    </text>
                  </g>
                ) : (
                  <g>
                    <rect x={node.x-14} y={node.y-14} width="28" height="28" rx="6" className={`junction-box ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#fff' }} />
                    {isHighlighted && <circle cx={node.x} cy={node.y} r={22} fill="url(#activeGrad)" opacity="0.1" className="animate-pulse" />}
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="8" fontWeight="black" fill={isHighlighted ? "#fff" : "#555"}>{node.id}</text>
                    {rawLabel && (
                      <g className="pointer-events-none">
                         {isSpineNode && hasMultiple ? (
                          <>
                            <rect x={node.x - 76} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x - 22} y={node.y} textAnchor="end" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[0]}</text>
                            <rect x={node.x + 18} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x + 22} y={node.y} textAnchor="start" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[1]}</text>
                          </>
                         ) : (
                          <g>
                             <rect x={isLeftSide ? node.x - 76 : node.x + 18} y={node.y - (hasMultiple ? 14 : 9)} width="58" height={hasMultiple ? 28 : 18} rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                             <text x={isLeftSide ? node.x - 22 : node.x + 22} y={node.y} textAnchor={isLeftSide ? "end" : "start"} dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">
                               {hasMultiple ? (<><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="-0.5em">{labelParts[0]}</tspan><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="1.1em">{labelParts[1]}</tspan></>) : rawLabel}
                             </text>
                          </g>
                         )}
                      </g>
                    )}
                  </g>
                )}
              </g>
            );
          })}
        </svg>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#02040a] animate-in fade-in zoom-in duration-500 overflow-y-auto custom-scrollbar">
      <aside className="w-full lg:w-[420px] p-6 lg:p-8 border-b lg:border-r border-white/10 flex flex-col space-y-4 md:space-y-6 bg-black/40 backdrop-blur-xl shrink-0 overflow-visible">
        <div className="flex justify-between items-start shrink-0">
          <div className="space-y-1">
            <h2 className="text-xl md:text-2xl font-black text-white tracking-tighter uppercase italic leading-tight">
              Photosynthesis:
              <span className="block text-[10px] md:text-sm font-bold tracking-widest text-cyan-400 mt-1 not-italic">
                Harvesting Love and Intelligence in Form
              </span>
            </h2>
            <div className="flex flex-wrap gap-1.5 mt-2">
               {[0, 1, 2, 3].map(n => (
                 <button key={n} onClick={() => handlePreset(n)} className={`w-8 h-8 md:w-9 md:h-9 rounded-lg border font-black text-[9px] md:text-[10px] transition-all ${n === 0 ? 'bg-white/5 border-white/10 text-gray-500' : 'bg-cyan-950/20 border-cyan-500/30 text-cyan-400 hover:bg-cyan-500 hover:text-black'}`}>
                   {n === 0 ? 'CLR' : `P${n}`}
                 </button>
               ))}
               <button onClick={() => handleSyncFromWheel('full')} className="px-2 md:px-3 h-8 md:h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[9px] md:text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 1</button>
               <button onClick={() => handleSyncFromWheel('title')} className="px-2 md:px-3 h-8 md:h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[9px] md:text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 2</button>
            </div>
          </div>
          <button onClick={onClose} className="p-2 md:p-3 rounded-2xl bg-white/5 text-gray-400 hover:text-white transition-all hover:bg-white/10 shrink-0">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 md:h-6 md:w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="space-y-3 md:space-y-4">
          {labels.map((label, idx) => {
            let mappedNodeId = -1;
            for(let ni=0; ni<12; ni++) {
              if(getDisplayIdx(ni, labelOffset, activeMode) === idx) {
                mappedNodeId = ni + 1;
                break;
              }
            }
            const isCurrentlyActive = highlightedNodes.includes(mappedNodeId);

            return (
              <div key={idx} className={`group relative p-0.5 transition-all duration-300 ${isCurrentlyActive ? 'scale-[1.01] md:scale-[1.02]' : ''}`}>
                <div className="flex justify-between items-end mb-1 px-1">
                  <label className="text-[8px] md:text-[9px] text-gray-500 uppercase tracking-widest font-black block">Leaf {idx + 1}</label>
                </div>
                <input 
                  type="text" value={label} onChange={(e) => updateLabel(idx, e.target.value)} placeholder={`Terminal input ${idx + 1}...`}
                  className={`w-full bg-white/5 border rounded-lg md:rounded-xl px-3 py-2 md:px-4 md:py-3 text-xs md:text-sm font-medium focus:bg-cyan-950/10 outline-none transition-all placeholder-gray-800 ${isCurrentlyActive ? 'border-cyan-500/50 text-white' : 'border-white/5 text-cyan-50/70'}`}
                />
              </div>
            );
          })}
        </div>

        <div className="pt-4 md:pt-6 border-t border-white/5 space-y-3 md:space-y-4 shrink-0 pb-6 bg-black/20 -mx-6 md:-mx-8 px-6 md:px-8">
          <div className="flex justify-between items-baseline px-1">
            <h3 className="text-[10px] md:text-xs font-black text-gray-500 uppercase tracking-[0.2em]">Flow of Life</h3>
            <span className="font-mono text-[10px] md:text-[11px] text-cyan-500 px-2 py-0.5 rounded bg-cyan-950/30">Phase: {labelOffset + 1}</span>
          </div>
          <div className="flex p-1 bg-white/5 rounded-xl md:rounded-2xl gap-1">
            <button onClick={() => { setActiveMode('linear'); setIsCycling(false); }} className={`flex-1 py-2 md:py-3 rounded-lg md:rounded-xl text-[9px] md:text-[10px] font-black tracking-widest transition-all ${activeMode === 'linear' ? 'bg-cyan-500 text-black shadow-lg shadow-cyan-500/20' : 'text-gray-400'}`}>LINEAR</button>
            <button onClick={() => { setActiveMode('bifurcation'); setIsCycling(false); }} className={`flex-1 py-2 md:py-3 rounded-lg md:rounded-xl text-[9px] md:text-[10px] font-black tracking-widest transition-all ${activeMode === 'bifurcation' ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-600/20' : 'text-gray-400'}`}>BIFURCATE</button>
          </div>
          <div className="grid grid-cols-2 gap-2 md:gap-3">
            <button onClick={() => handleShift('down')} className="bg-white/5 hover:bg-cyan-500/10 py-3 md:py-4 rounded-xl md:rounded-2xl border border-white/5 text-base md:text-lg font-black tracking-widest transition-all uppercase">-</button>
            <button onClick={() => handleShift('up')} className="bg-white/5 hover:bg-cyan-500/10 py-3 md:py-4 rounded-xl md:rounded-2xl border border-white/5 text-base md:text-lg font-black tracking-widest transition-all uppercase">+</button>
          </div>
          <button onClick={() => setIsCycling(!isCycling)} className={`w-full py-3 md:py-4 rounded-xl md:rounded-2xl border font-black text-[10px] md:text-[11px] tracking-[0.2em] transition-all uppercase ${isCycling ? 'bg-red-600 text-white shadow-xl' : 'bg-cyan-600/10 text-cyan-400 border-cyan-500/20 hover:border-cyan-500/50'}`}>
            {isCycling ? 'Stop Stream' : `Animate Stream`}
          </button>
        </div>
      </aside>

      <div className="flex-1 w-full flex items-center justify-center p-0 lg:p-12 pb-20 lg:pb-0">
        <div className="w-full h-auto min-h-[60vh] md:min-h-[80vh] lg:h-full flex items-center justify-center">
          {renderDiagram()}
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(6, 182, 212, 0.15); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(6, 182, 212, 0.3); }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default TreeOfLifeMode;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { KATHARA_GRID_NODES, KATHARA_GRID_LINES, KATHARA_CLOCK_POINTS, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, MUQATTAT_LETTERS } from '../constants.ts';
import { getSliceAtPoint } from '../utils.ts';

interface TreeOfLifeModeProps {
  rotation: number;
  onClose: () => void;
}

const PRESET_1 = [
  "Book", "Chosen One | Rasul", "Sign", "Prophet", "Challenge | Rescue", "Curse", 
  "Blessed Land", "Believer | Servant", "Suhuf", "Teacher", "Witness | Driver", "Stone"
];

const PRESET_2 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Heifer",
  "Stone",
  "Boat | Bee",
  "Noah | Musa",
  "Idris | Isa",
  "Tree | Mountain",
  "Amanah",
  "Return",
  "Solomon | Dawud",
  "Book | Yahya"
];

const PRESET_3 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Rushd",
  "Stone",
  "Iron | Wood",
  "Noah | Musa",
  "Idris | Isa",
  "Iron | Mountain",
  "Amanah",
  "Dawud",
  "Solomon | Death",
  "Book | Yahya"
];

interface BifurcationStage {
  main: number[];
  manualLines: [number, number][];
  isBlackPhase?: boolean;
}

const TreeOfLifeMode: React.FC<TreeOfLifeModeProps> = ({ rotation, onClose }) => {
  const [labels, setLabels] = useState<string[]>(Array(12).fill(''));
  const [labelOffset, setLabelOffset] = useState(0); 
  const [isCycling, setIsCycling] = useState(false);
  const [activeMode, setActiveMode] = useState<'linear' | 'bifurcation'>('linear');
  const [highlightedNodes, setHighlightedNodes] = useState<number[]>([]);

  const [showLightning, setShowLightning] = useState(false);
  const [showExplosion, setShowExplosion] = useState(false);

  // Domain Node Sets
  const BLUE_NODES = [1, 2, 3, 4, 5, 6, 13];
  const GREEN_NODES = [12, 11, 10, 9, 8, 7, 15];

  const LOOP_LINES: [number, number][] = [[2, 3], [3, 6], [6, 9], [9, 11], [11, 10], [10, 7], [7, 4], [4, 2]];
  const BOLT_3_10_LINES: [number, number][] = [[3, 13], [4, 13], [4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9], [9, 15], [10, 15]];
  const BOLT_4_9_LINES: [number, number][] = [[4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9]];
  const PATH_5_8_LINES: [number, number][] = [[5, 6], [6, 14], [7, 14], [7, 8]];
  const CROSS_PLUS_LINES: [number, number][] = [[6, 14], [7, 14], [5, 14], [14, 8], [6, 7], [5, 8]];

  const DUAL_GROUP_LINES: [number, number][] = [
    [1, 2], [2, 3], [2, 4], [2, 13], [3, 13], [4, 13], [3, 5], [4, 5], [5, 6], [3, 6], [13, 5],
    [12, 11], [11, 10], [11, 9], [9, 15], [10, 15], [15, 8], [8, 9], [8, 10], [7, 8], [7, 10], [15, 11]
  ];
  const SQUARE_PLUS_LINES: [number, number][] = [[5, 6], [5, 7], [6, 8], [7, 8], [6, 14], [14, 7], [5, 14], [14, 8]];

  const BIFURCATION_STAGES: BifurcationStage[] = useMemo(() => [
    { main: [1, 12], manualLines: [], isBlackPhase: true },
    { main: [2, 11], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: CROSS_PLUS_LINES },
    { main: [12, 1], manualLines: DUAL_GROUP_LINES },
    { main: [11, 2], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: SQUARE_PLUS_LINES },
  ], []);

  const handleSyncFromWheel = (mode: 'full' | 'title') => {
    const newLabels = KATHARA_CLOCK_POINTS.map(pointValue => {
        const slice = getSliceAtPoint(pointValue, rotation);
        const chapterInfo = CHAPTER_DETAILS.find(c => c.number === slice.id);
        const title = chapterInfo?.englishName || 'Unknown';
        const letters = MUQATTAT_LETTERS.get(slice.id)?.join(' ') || '';
        if (mode === 'title') return `${title}${letters ? ` | ${letters}` : ''}`;
        return `${slice.id} ${title}${letters ? ` | ${letters}` : ''}`;
    });
    setLabels(newLabels);
    setLabelOffset(0);
  };

  const handlePreset = (num: number) => {
    setLabelOffset(0);
    setHighlightedNodes([]);
    setIsCycling(false);
    if (num === 0) setLabels(Array(12).fill(''));
    else if (num === 1) setLabels([...PRESET_1]);
    else if (num === 2) setLabels([...PRESET_2]);
    else if (num === 3) setLabels([...PRESET_3]);
  };

  const updateVisuals = useCallback((offset: number) => {
    if (activeMode === 'linear') setHighlightedNodes([offset + 1]);
    else setHighlightedNodes(BIFURCATION_STAGES[offset].main);
  }, [activeMode, BIFURCATION_STAGES]);

  const handleShift = useCallback((direction: 'up' | 'down') => {
    setLabelOffset((prev) => {
      const next = direction === 'up' ? (prev + 1) % 12 : (prev - 1 + 12) % 12;
      if (activeMode === 'bifurcation') {
        if (prev === 11 && next === 0) { setShowLightning(true); setTimeout(() => setShowLightning(false), 800); }
        if (prev === 5 && next === 6) { setShowExplosion(true); setTimeout(() => setShowExplosion(false), 1200); }
      }
      updateVisuals(next);
      return next;
    });
  }, [updateVisuals, activeMode]);

  useEffect(() => { updateVisuals(labelOffset); }, [activeMode, updateVisuals, labelOffset]);

  useEffect(() => {
    if (!isCycling) return;
    const intervalId = window.setInterval(() => { handleShift('up'); }, 1800);
    return () => clearInterval(intervalId);
  }, [isCycling, handleShift]);

  const updateLabel = (index: number, val: string) => {
    const next = [...labels];
    next[index] = val;
    setLabels(next);
  };

  const getLineStatus = useCallback((from: number, to: number, h: number[], offset: number) => {
    if (activeMode === 'linear') {
      const nodeId = h[0];
      return from === nodeId || to === nodeId ? 'main' : null;
    }
    const stage = BIFURCATION_STAGES[offset];
    if (stage.isBlackPhase) return 'black';
    const isManual = stage.manualLines?.some(l => (l[0] === from && l[1] === to) || (l[0] === to && l[1] === from));
    return isManual ? 'main' : null;
  }, [activeMode, BIFURCATION_STAGES]);

  const getDisplayIdx = useCallback((nodeIdx: number, offset: number, mode: 'linear' | 'bifurcation') => {
    if (mode === 'linear') return (nodeIdx - offset + 12) % 12;
    const step = offset % 6;
    const hasCrossed = offset >= 6;
    if (nodeIdx < 6) return hasCrossed ? (nodeIdx - step + 6) % 6 + 6 : (nodeIdx - step + 6) % 6;
    return hasCrossed ? (11 - nodeIdx - step + 6) % 6 : (11 - nodeIdx - step + 6) % 6 + 6;
  }, []);

  const renderDiagram = () => {
    const isPhase2or8 = activeMode === 'bifurcation' && (labelOffset === 1 || labelOffset === 7);
    const extraSilverLines = isPhase2or8 ? [[9, 7], [6, 4]] : [];

    return (
      <div className="relative flex items-center justify-center bg-black/80 overflow-hidden h-full w-full rounded-2xl lg:rounded-none">
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[100%] h-[100%] rounded-full bg-cyan-950/10 blur-[80px] lg:blur-[180px]"></div>
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000_100%)] opacity-80"></div>
        </div>

        <style>{`
          .node-glow { filter: drop-shadow(0 0 15px currentColor); }
          .kathara-svg { width: 100%; height: auto; display: block; max-height: 85vh; }
          .junction-box { stroke-width: 1; fill: rgba(0, 0, 0, 0.85); stroke: rgba(255, 255, 255, 0.1); }
          .active-junction { stroke: #fff; stroke-width: 1.5; fill: rgba(8, 145, 178, 0.3); }
          .filter-junction { stroke: #06b6d4; fill: rgba(0, 30, 40, 0.9); }

          @keyframes flow-up { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }
          @keyframes flow-down { 0% { stroke-dashoffset: 0; } 100% { stroke-dashoffset: 40; } }
          @keyframes flow-silver { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }

          .liquid-blue-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-up 1.6s linear infinite; filter: drop-shadow(0 0 6px #06b6d4); }
          .liquid-green-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-down 1.6s linear infinite; filter: drop-shadow(0 0 6px #4ade80); }
          .liquid-silver-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-silver 1.6s linear infinite; filter: drop-shadow(0 0 6px #cbd5e1); }

          @keyframes spark { 0%, 100% { opacity: 0; stroke-width: 1; } 20% { opacity: 1; stroke-width: 4; } 60% { opacity: 1; stroke-width: 2; } }
          .lightning-bolt { stroke: #fff; filter: drop-shadow(0 0 12px cyan); animation: spark 0.25s infinite; }

          @keyframes blast { 0% { transform: scale(0); opacity: 1; filter: blur(0px); } 50% { transform: scale(3); opacity: 0.5; filter: blur(5px); } 100% { transform: scale(4.5); opacity: 0; filter: blur(10px); } }
          .fire-burst { fill: #f97316; animation: blast 0.8s ease-out forwards; }
        `}</style>

        <svg viewBox="-70 0 290 280" className="kathara-svg drop-shadow-[0_0_80px_rgba(6,182,212,0.15)]">
          <defs>
            <linearGradient id="activeGrad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#0891b2" />
              <stop offset="100%" stopColor="#06b6d4" />
            </linearGradient>
          </defs>

          <g>
            {KATHARA_GRID_LINES.map((line, index) => {
              const fromNode = KATHARA_GRID_NODES.find(n => n.id === line.from);
              const toNode = KATHARA_GRID_NODES.find(n => n.id === line.to);
              if (!fromNode || !toNode) return null;

              const status = getLineStatus(line.from, line.to, highlightedNodes, labelOffset);
              const isMain = status === 'main';
              const isAscending = fromNode.y > toNode.y;

              const isBlueDomain = (BLUE_NODES.includes(line.from) && BLUE_NODES.includes(line.to)) || 
                                  ((line.from === 14 || line.to === 14) && (BLUE_NODES.includes(line.from) || BLUE_NODES.includes(line.to)));

              const isGreenDomain = (GREEN_NODES.includes(line.from) && GREEN_NODES.includes(line.to)) || 
                                   ((line.from === 14 || line.to === 14) && (GREEN_NODES.includes(line.from) || GREEN_NODES.includes(line.to)));

              const isPhase12 = activeMode === 'bifurcation' && labelOffset === 11;
              const isSilverLine = isPhase12 && (
                (line.from === 6 && line.to === 8) || (line.from === 8 && line.to === 6) ||
                (line.from === 8 && line.to === 7) || (line.from === 7 && line.to === 8) ||
                (line.from === 7 && line.to === 5) || (line.from === 5 && line.to === 7) ||
                (line.from === 5 && line.to === 6) || (line.from === 6 && line.to === 5)
              );

              const showBlue = activeMode === 'linear' ? isMain : (isMain && isBlueDomain && !isSilverLine);
              const showGreen = activeMode === 'linear' ? isMain : (isMain && isGreenDomain && !isSilverLine);
              const showSilver = isMain && isSilverLine;

              const dx = toNode.x - fromNode.x;
              const dy = toNode.y - fromNode.y;
              const len = Math.sqrt(dx*dx + dy*dy);
              const nx = -dy / (len || 1);
              const ny = dx / (len || 1);
              const offsetDist = activeMode === 'linear' ? 2.0 : 0;

              return (
                <g key={index}>
                  <line 
                    x1={fromNode.x} y1={fromNode.y} 
                    x2={toNode.x} y2={toNode.y} 
                    stroke={isMain ? (isSilverLine ? "rgba(203,213,225,0.2)" : "rgba(255,255,255,0.12)") : status === 'black' ? "#0a0a0a" : "rgba(255,255,255,0.04)"}
                    strokeWidth={isMain ? 4 : 1}
                    className="transition-all duration-700"
                  />
                  {showBlue && <line x1={(isAscending ? fromNode.x : toNode.x) + nx * offsetDist} y1={(isAscending ? fromNode.y : toNode.y) + ny * offsetDist} x2={(isAscending ? toNode.x : fromNode.x) + nx * offsetDist} y2={(isAscending ? toNode.y : fromNode.y) + ny * offsetDist} stroke="#06b6d4" strokeWidth="3.5" className="liquid-blue-flow" />}
                  {showGreen && <line x1={(isAscending ? toNode.x : fromNode.x) - nx * offsetDist} y1={(isAscending ? toNode.y : fromNode.y) - ny * offsetDist} x2={(isAscending ? fromNode.x : toNode.x) - nx * offsetDist} y2={(isAscending ? fromNode.y : toNode.y) - ny * offsetDist} stroke="#4ade80" strokeWidth="3.5" className="liquid-green-flow" />}
                  {showSilver && <line x1={fromNode.x} y1={fromNode.y} x2={toNode.x} y2={toNode.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />}
                </g>
              );
            })}
            {extraSilverLines.map(([fromId, toId], idx) => {
              const f = KATHARA_GRID_NODES.find(n => n.id === fromId);
              const t = KATHARA_GRID_NODES.find(n => n.id === toId);
              if (!f || !t) return null;
              return (
                <g key={`extra-silver-${idx}`}>
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="rgba(203,213,225,0.4)" strokeWidth="3" />
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />
                </g>
              );
            })}
          </g>

          {showLightning && (
            <g className="pointer-events-none">
              <path d="M 75 20 L 95 60 L 55 100 L 75 140" fill="none" className="lightning-bolt" />
              <path d="M 30 140 L 55 170 L 35 200 L 75 240" fill="none" className="lightning-bolt" />
              <path d="M 120 140 L 95 170 L 115 200 L 75 240" fill="none" className="lightning-bolt" />
            </g>
          )}

          {showExplosion && (
            <g transform="translate(75, 140)" className="pointer-events-none">
              <circle r="12" className="fire-burst" />
              <circle r="8" className="fire-burst" style={{ animationDelay: '0.1s' }} />
            </g>
          )}

          {KATHARA_GRID_NODES.map((node, nodeIdx) => {
            const isFilter = node.id > 12;
            const isHighlighted = highlightedNodes.includes(node.id);
            const displayLabelIdx = isFilter ? -1 : getDisplayIdx(nodeIdx, labelOffset, activeMode);
            const rawLabel = isFilter ? '' : labels[displayLabelIdx];

            const filterFullLabel = node.id === 13 ? '△108⚡' : node.id === 14 ? '🔥103🐟' : node.id === 15 ? '⚫110🌳' : null;

            const labelParts = rawLabel ? rawLabel.split('|').map(p => p.trim()) : [];
            const hasMultiple = labelParts.length > 1;
            const isSpineNode = node.x === 75 && node.id <= 12; 
            const isLeftSide = node.x < 75;

            return (
              <g key={node.id} className="transition-all duration-500">
                {isFilter ? (
                  <g>
                    {isHighlighted && <rect x={node.x-28} y={node.y-12} width="56" height="24" rx="4" fill="rgba(6,182,212,0.15)" className="animate-pulse" />}
                    <rect x={node.x-25} y={node.y-10} width="50" height="20" rx="3" className={`filter-junction ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#06b6d4' }} />
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#0891b2"} className="font-mono tracking-tighter" style={{ pointerEvents: 'none' }}>
                      {filterFullLabel}
                    </text>
                  </g>
                ) : (
                  <g>
                    <rect x={node.x-14} y={node.y-14} width="28" height="28" rx="6" className={`junction-box ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#fff' }} />
                    {isHighlighted && <circle cx={node.x} cy={node.y} r={22} fill="url(#activeGrad)" opacity="0.1" className="animate-pulse" />}
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="8" fontWeight="black" fill={isHighlighted ? "#fff" : "#555"}>{node.id}</text>
                    {rawLabel && (
                      <g className="pointer-events-none">
                         {isSpineNode && hasMultiple ? (
                          <>
                            <rect x={node.x - 76} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x - 22} y={node.y} textAnchor="end" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[0]}</text>
                            <rect x={node.x + 18} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x + 22} y={node.y} textAnchor="start" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[1]}</text>
                          </>
                         ) : (
                          <g>
                             <rect x={isLeftSide ? node.x - 76 : node.x + 18} y={node.y - (hasMultiple ? 14 : 9)} width="58" height={hasMultiple ? 28 : 18} rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                             <text x={isLeftSide ? node.x - 22 : node.x + 22} y={node.y} textAnchor={isLeftSide ? "end" : "start"} dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">
                               {hasMultiple ? (<><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="-0.5em">{labelParts[0]}</tspan><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="1.1em">{labelParts[1]}</tspan></>) : rawLabel}
                             </text>
                          </g>
                         )}
                      </g>
                    )}
                  </g>
                )}
              </g>
            );
          })}
        </svg>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#02040a] animate-in fade-in zoom-in duration-500 overflow-y-auto lg:overflow-hidden custom-scrollbar">
      <aside className="w-full lg:w-[420px] p-6 lg:p-8 lg:h-full lg:overflow-y-auto border-b lg:border-r border-white/10 flex flex-col space-y-4 md:space-y-6 bg-black/40 backdrop-blur-xl shrink-0 custom-scrollbar">
        <div className="flex justify-between items-start shrink-0">
          <div className="space-y-1">
            <h2 className="text-xl md:text-2xl font-black text-white tracking-tighter uppercase italic leading-tight">
              Photosynthesis:
              <span className="block text-[10px] md:text-sm font-bold tracking-widest text-cyan-400 mt-1 not-italic">
                Harvesting Love and Intelligence in Form
              </span>
            </h2>
            <div className="flex flex-wrap gap-1.5 mt-2">
               {[0, 1, 2, 3].map(n => (
                 <button key={n} onClick={() => handlePreset(n)} className={`w-8 h-8 md:w-9 md:h-9 rounded-lg border font-black text-[9px] md:text-[10px] transition-all ${n === 0 ? 'bg-white/5 border-white/10 text-gray-500' : 'bg-cyan-950/20 border-cyan-500/30 text-cyan-400 hover:bg-cyan-500 hover:text-black'}`}>
                   {n === 0 ? 'CLR' : `P${n}`}
                 </button>
               ))}
               <button onClick={() => handleSyncFromWheel('full')} className="px-2 md:px-3 h-8 md:h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[9px] md:text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 1</button>
               <button onClick={() => handleSyncFromWheel('title')} className="px-2 md:px-3 h-8 md:h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[9px] md:text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 2</button>
            </div>
          </div>
          <button onClick={onClose} className="p-2 md:p-3 rounded-2xl bg-white/5 text-gray-400 hover:text-white transition-all hover:bg-white/10 shrink-0">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 md:h-6 md:w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="space-y-3 md:space-y-4">
          {labels.map((label, idx) => {
            let mappedNodeId = -1;
            for(let ni=0; ni<12; ni++) {
              if(getDisplayIdx(ni, labelOffset, activeMode) === idx) {
                mappedNodeId = ni + 1;
                break;
              }
            }
            const isCurrentlyActive = highlightedNodes.includes(mappedNodeId);

            return (
              <div key={idx} className={`group relative p-0.5 transition-all duration-300 ${isCurrentlyActive ? 'scale-[1.01] md:scale-[1.02]' : ''}`}>
                <div className="flex justify-between items-end mb-1 px-1">
                  <label className="text-[8px] md:text-[9px] text-gray-500 uppercase tracking-widest font-black block">Leaf {idx + 1}</label>
                </div>
                <input 
                  type="text" value={label} onChange={(e) => updateLabel(idx, e.target.value)} placeholder={`Terminal input ${idx + 1}...`}
                  className={`w-full bg-white/5 border rounded-lg md:rounded-xl px-3 py-2 md:px-4 md:py-3 text-xs md:text-sm font-medium focus:bg-cyan-950/10 outline-none transition-all placeholder-gray-800 ${isCurrentlyActive ? 'border-cyan-500/50 text-white' : 'border-white/5 text-cyan-50/70'}`}
                />
              </div>
            );
          })}
        </div>

        <div className="pt-4 md:pt-6 border-t border-white/5 space-y-3 md:space-y-4 shrink-0 pb-6 bg-black/20 -mx-6 md:-mx-8 px-6 md:px-8">
          <div className="flex justify-between items-baseline px-1">
            <h3 className="text-[10px] md:text-xs font-black text-gray-500 uppercase tracking-[0.2em]">Flow of Life</h3>
            <span className="font-mono text-[10px] md:text-[11px] text-cyan-500 px-2 py-0.5 rounded bg-cyan-950/30">Phase: {labelOffset + 1}</span>
          </div>
          <div className="flex p-1 bg-white/5 rounded-xl md:rounded-2xl gap-1">
            <button onClick={() => { setActiveMode('linear'); setIsCycling(false); }} className={`flex-1 py-2 md:py-3 rounded-lg md:rounded-xl text-[9px] md:text-[10px] font-black tracking-widest transition-all ${activeMode === 'linear' ? 'bg-cyan-500 text-black shadow-lg shadow-cyan-500/20' : 'text-gray-400'}`}>LINEAR</button>
            <button onClick={() => { setActiveMode('bifurcation'); setIsCycling(false); }} className={`flex-1 py-2 md:py-3 rounded-lg md:rounded-xl text-[9px] md:text-[10px] font-black tracking-widest transition-all ${activeMode === 'bifurcation' ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-600/20' : 'text-gray-400'}`}>BIFURCATE</button>
          </div>
          <div className="grid grid-cols-2 gap-2 md:gap-3">
            <button onClick={() => handleShift('down')} className="bg-white/5 hover:bg-cyan-500/10 py-3 md:py-4 rounded-xl md:rounded-2xl border border-white/5 text-base md:text-lg font-black tracking-widest transition-all uppercase">-</button>
            <button onClick={() => handleShift('up')} className="bg-white/5 hover:bg-cyan-500/10 py-3 md:py-4 rounded-xl md:rounded-2xl border border-white/5 text-base md:text-lg font-black tracking-widest transition-all uppercase">+</button>
          </div>
          <button onClick={() => setIsCycling(!isCycling)} className={`w-full py-3 md:py-4 rounded-xl md:rounded-2xl border font-black text-[10px] md:text-[11px] tracking-[0.2em] transition-all uppercase ${isCycling ? 'bg-red-600 text-white shadow-xl' : 'bg-cyan-600/10 text-cyan-400 border-cyan-500/20 hover:border-cyan-500/50'}`}>
            {isCycling ? 'Stop Stream' : `Animate Stream`}
          </button>
        </div>
      </aside>

      <div className="flex-1 w-full flex items-center justify-center p-0 lg:p-12 pb-20 lg:pb-0 lg:h-full lg:overflow-hidden">
        <div className="w-full h-auto min-h-[60vh] md:min-h-[80vh] lg:h-full lg:min-h-0 flex items-center justify-center">
          {renderDiagram()}
        </div>
      </div>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(6, 182, 212, 0.15); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(6, 182, 212, 0.3); }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default TreeOfLifeMode;

import React, { useState, useEffect, useCallback, useMemo } from 'react';
import { KATHARA_GRID_NODES, KATHARA_GRID_LINES, KATHARA_CLOCK_POINTS, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, MUQATTAT_LETTERS } from '../constants.ts';
import { getSliceAtPoint } from '../utils.ts';

interface TreeOfLifeModeProps {
  rotation: number;
  onClose: () => void;
}

const PRESET_1 = [
  "Book", "Chosen One | Rasul", "Sign", "Prophet", "Challenge | Rescue", "Curse", 
  "Blessed Land", "Believer | Servant", "Suhuf", "Teacher", "Witness | Driver", "Stone"
];

const PRESET_2 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Heifer",
  "Stone",
  "Boat | Bee",
  "Noah | Musa",
  "Idris | Isa",
  "Tree | Mountain",
  "Amanah",
  "Return",
  "Solomon | Dawud",
  "Book | Yahya"
];

const PRESET_3 = [
  "Ibrahim | Ahmed",
  "Ishac | Ishmail",
  "Rushd",
  "Stone",
  "Iron | Wood",
  "Noah | Musa",
  "Idris | Isa",
  "Iron | Mountain",
  "Amanah",
  "Dawud",
  "Solomon | Death",
  "Book | Yahya"
];

interface BifurcationStage {
  main: number[];
  manualLines: [number, number][];
  isBlackPhase?: boolean;
}

const TreeOfLifeMode: React.FC<TreeOfLifeModeProps> = ({ rotation, onClose }) => {
  const [labels, setLabels] = useState<string[]>(Array(12).fill(''));
  const [labelOffset, setLabelOffset] = useState(0); 
  const [isCycling, setIsCycling] = useState(false);
  const [activeMode, setActiveMode] = useState<'linear' | 'bifurcation'>('linear');
  const [highlightedNodes, setHighlightedNodes] = useState<number[]>([]);

  const [showLightning, setShowLightning] = useState(false);
  const [showExplosion, setShowExplosion] = useState(false);

  // Domain Node Sets
  const BLUE_NODES = [1, 2, 3, 4, 5, 6, 13];
  const GREEN_NODES = [12, 11, 10, 9, 8, 7, 15];

  const LOOP_LINES: [number, number][] = [[2, 3], [3, 6], [6, 9], [9, 11], [11, 10], [10, 7], [7, 4], [4, 2]];
  const BOLT_3_10_LINES: [number, number][] = [[3, 13], [4, 13], [4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9], [9, 15], [10, 15]];
  const BOLT_4_9_LINES: [number, number][] = [[4, 5], [5, 6], [6, 14], [7, 14], [7, 8], [8, 9]];
  const PATH_5_8_LINES: [number, number][] = [[5, 6], [6, 14], [7, 14], [7, 8]];
  const CROSS_PLUS_LINES: [number, number][] = [[6, 14], [7, 14], [5, 14], [14, 8], [6, 7], [5, 8]];

  const DUAL_GROUP_LINES: [number, number][] = [
    [1, 2], [2, 3], [2, 4], [2, 13], [3, 13], [4, 13], [3, 5], [4, 5], [5, 6], [3, 6], [13, 5],
    [12, 11], [11, 10], [11, 9], [9, 15], [10, 15], [15, 8], [8, 9], [8, 10], [7, 8], [7, 10], [15, 11]
  ];
  const SQUARE_PLUS_LINES: [number, number][] = [[5, 6], [5, 7], [6, 8], [7, 8], [6, 14], [14, 7], [5, 14], [14, 8]];

  const BIFURCATION_STAGES: BifurcationStage[] = useMemo(() => [
    { main: [1, 12], manualLines: [], isBlackPhase: true },
    { main: [2, 11], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: CROSS_PLUS_LINES },
    { main: [12, 1], manualLines: DUAL_GROUP_LINES },
    { main: [11, 2], manualLines: LOOP_LINES },
    { main: [3, 10], manualLines: BOLT_3_10_LINES },
    { main: [4, 9],  manualLines: BOLT_4_9_LINES },
    { main: [5, 8],  manualLines: PATH_5_8_LINES },
    { main: [6, 7],  manualLines: SQUARE_PLUS_LINES },
  ], []);

  const handleSyncFromWheel = (mode: 'full' | 'title') => {
    const newLabels = KATHARA_CLOCK_POINTS.map(pointValue => {
        const slice = getSliceAtPoint(pointValue, rotation);
        const chapterInfo = CHAPTER_DETAILS.find(c => c.number === slice.id);
        const title = chapterInfo?.englishName || 'Unknown';
        const letters = MUQATTAT_LETTERS.get(slice.id)?.join(' ') || '';
        if (mode === 'title') return `${title}${letters ? ` | ${letters}` : ''}`;
        return `${slice.id} ${title}${letters ? ` | ${letters}` : ''}`;
    });
    setLabels(newLabels);
    setLabelOffset(0);
  };

  const handlePreset = (num: number) => {
    setLabelOffset(0);
    setHighlightedNodes([]);
    setIsCycling(false);
    if (num === 0) setLabels(Array(12).fill(''));
    else if (num === 1) setLabels([...PRESET_1]);
    else if (num === 2) setLabels([...PRESET_2]);
    else if (num === 3) setLabels([...PRESET_3]);
  };

  const updateVisuals = useCallback((offset: number) => {
    if (activeMode === 'linear') setHighlightedNodes([offset + 1]);
    else setHighlightedNodes(BIFURCATION_STAGES[offset].main);
  }, [activeMode, BIFURCATION_STAGES]);

  const handleShift = useCallback((direction: 'up' | 'down') => {
    setLabelOffset((prev) => {
      const next = direction === 'up' ? (prev + 1) % 12 : (prev - 1 + 12) % 12;
      if (activeMode === 'bifurcation') {
        if (prev === 11 && next === 0) { setShowLightning(true); setTimeout(() => setShowLightning(false), 800); }
        if (prev === 5 && next === 6) { setShowExplosion(true); setTimeout(() => setShowExplosion(false), 1200); }
      }
      updateVisuals(next);
      return next;
    });
  }, [updateVisuals, activeMode]);

  useEffect(() => { updateVisuals(labelOffset); }, [activeMode, updateVisuals, labelOffset]);

  useEffect(() => {
    if (!isCycling) return;
    const intervalId = window.setInterval(() => { handleShift('up'); }, 1800);
    return () => clearInterval(intervalId);
  }, [isCycling, handleShift]);

  const updateLabel = (index: number, val: string) => {
    const next = [...labels];
    next[index] = val;
    setLabels(next);
  };

  const getLineStatus = useCallback((from: number, to: number, h: number[], offset: number) => {
    if (activeMode === 'linear') {
      const nodeId = h[0];
      return from === nodeId || to === nodeId ? 'main' : null;
    }
    const stage = BIFURCATION_STAGES[offset];
    if (stage.isBlackPhase) return 'black';
    const isManual = stage.manualLines?.some(l => (l[0] === from && l[1] === to) || (l[0] === to && l[1] === from));
    return isManual ? 'main' : null;
  }, [activeMode, BIFURCATION_STAGES]);

  const getDisplayIdx = useCallback((nodeIdx: number, offset: number, mode: 'linear' | 'bifurcation') => {
    if (mode === 'linear') return (nodeIdx - offset + 12) % 12;
    const step = offset % 6;
    const hasCrossed = offset >= 6;
    if (nodeIdx < 6) return hasCrossed ? (nodeIdx - step + 6) % 6 + 6 : (nodeIdx - step + 6) % 6;
    return hasCrossed ? (11 - nodeIdx - step + 6) % 6 : (11 - nodeIdx - step + 6) % 6 + 6;
  }, []);

  const renderDiagram = () => {
    const isPhase2or8 = activeMode === 'bifurcation' && (labelOffset === 1 || labelOffset === 7);
    const extraSilverLines = isPhase2or8 ? [[9, 7], [6, 4]] : [];

    return (
      <div className="relative flex items-center justify-center bg-black/80 overflow-hidden h-full w-full rounded-2xl lg:rounded-none">
        <div className="absolute inset-0 pointer-events-none">
          <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-full h-full rounded-full bg-cyan-950/10 blur-[100px]"></div>
          <div className="absolute inset-0 bg-[radial-gradient(circle_at_center,transparent_0%,#000_100%)] opacity-80"></div>
        </div>

        <style>{`
          .node-glow { filter: drop-shadow(0 0 15px currentColor); }
          .kathara-svg { width: 100%; height: 100%; display: block; max-height: 90vh; }
          .junction-box { stroke-width: 1; fill: rgba(0, 0, 0, 0.85); stroke: rgba(255, 255, 255, 0.1); }
          .active-junction { stroke: #fff; stroke-width: 1.5; fill: rgba(8, 145, 178, 0.3); }
          .filter-junction { stroke: #06b6d4; fill: rgba(0, 30, 40, 0.9); }

          @keyframes flow-up { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }
          @keyframes flow-down { 0% { stroke-dashoffset: 0; } 100% { stroke-dashoffset: 40; } }
          @keyframes flow-silver { 0% { stroke-dashoffset: 40; } 100% { stroke-dashoffset: 0; } }

          .liquid-blue-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-up 1.6s linear infinite; filter: drop-shadow(0 0 6px #06b6d4); }
          .liquid-green-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-down 1.6s linear infinite; filter: drop-shadow(0 0 6px #4ade80); }
          .liquid-silver-flow { stroke-dasharray: 0.1, 14; stroke-linecap: round; animation: flow-silver 1.6s linear infinite; filter: drop-shadow(0 0 6px #cbd5e1); }

          @keyframes spark { 0%, 100% { opacity: 0; stroke-width: 1; } 20% { opacity: 1; stroke-width: 4; } 60% { opacity: 1; stroke-width: 2; } }
          .lightning-bolt { stroke: #fff; filter: drop-shadow(0 0 12px cyan); animation: spark 0.25s infinite; }

          @keyframes blast { 0% { transform: scale(0); opacity: 1; filter: blur(0px); } 50% { transform: scale(3); opacity: 0.5; filter: blur(5px); } 100% { transform: scale(4.5); opacity: 0; filter: blur(10px); } }
          .fire-burst { fill: #f97316; animation: blast 0.8s ease-out forwards; }
        `}</style>

        <svg viewBox="-75 -20 300 320" className="kathara-svg drop-shadow-[0_0_80px_rgba(6,182,212,0.15)]">
          <defs>
            <linearGradient id="activeGrad" x1="0%" y1="0%" x2="100%" y2="100%">
              <stop offset="0%" stopColor="#0891b2" />
              <stop offset="100%" stopColor="#06b6d4" />
            </linearGradient>
          </defs>

          <g>
            {KATHARA_GRID_LINES.map((line, index) => {
              const fromNode = KATHARA_GRID_NODES.find(n => n.id === line.from);
              const toNode = KATHARA_GRID_NODES.find(n => n.id === line.to);
              if (!fromNode || !toNode) return null;

              const status = getLineStatus(line.from, line.to, highlightedNodes, labelOffset);
              const isMain = status === 'main';
              const isAscending = fromNode.y > toNode.y;

              const isBlueDomain = (BLUE_NODES.includes(line.from) && BLUE_NODES.includes(line.to)) || 
                                  ((line.from === 14 || line.to === 14) && (BLUE_NODES.includes(line.from) || BLUE_NODES.includes(line.to)));

              const isGreenDomain = (GREEN_NODES.includes(line.from) && GREEN_NODES.includes(line.to)) || 
                                   ((line.from === 14 || line.to === 14) && (GREEN_NODES.includes(line.from) || GREEN_NODES.includes(line.to)));

              const isPhase12 = activeMode === 'bifurcation' && labelOffset === 11;
              const isSilverLine = isPhase12 && (
                (line.from === 6 && line.to === 8) || (line.from === 8 && line.to === 6) ||
                (line.from === 8 && line.to === 7) || (line.from === 7 && line.to === 8) ||
                (line.from === 7 && line.to === 5) || (line.from === 5 && line.to === 7) ||
                (line.from === 5 && line.to === 6) || (line.from === 6 && line.to === 5)
              );

              const showBlue = activeMode === 'linear' ? isMain : (isMain && isBlueDomain && !isSilverLine);
              const showGreen = activeMode === 'linear' ? isMain : (isMain && isGreenDomain && !isSilverLine);
              const showSilver = isMain && isSilverLine;

              const dx = toNode.x - fromNode.x;
              const dy = toNode.y - fromNode.y;
              const len = Math.sqrt(dx*dx + dy*dy);
              const nx = -dy / (len || 1);
              const ny = dx / (len || 1);
              const offsetDist = activeMode === 'linear' ? 2.0 : 0;

              return (
                <g key={index}>
                  <line 
                    x1={fromNode.x} y1={fromNode.y} 
                    x2={toNode.x} y2={toNode.y} 
                    stroke={isMain ? (isSilverLine ? "rgba(203,213,225,0.2)" : "rgba(255,255,255,0.12)") : status === 'black' ? "#0a0a0a" : "rgba(255,255,255,0.04)"}
                    strokeWidth={isMain ? 4 : 1}
                    className="transition-all duration-700"
                  />
                  {showBlue && <line x1={(isAscending ? fromNode.x : toNode.x) + nx * offsetDist} y1={(isAscending ? fromNode.y : toNode.y) + ny * offsetDist} x2={(isAscending ? toNode.x : fromNode.x) + nx * offsetDist} y2={(isAscending ? toNode.y : fromNode.y) + ny * offsetDist} stroke="#06b6d4" strokeWidth="3.5" className="liquid-blue-flow" />}
                  {showGreen && <line x1={(isAscending ? toNode.x : fromNode.x) - nx * offsetDist} y1={(isAscending ? toNode.y : fromNode.y) - ny * offsetDist} x2={(isAscending ? fromNode.x : toNode.x) - nx * offsetDist} y2={(isAscending ? fromNode.y : toNode.y) - ny * offsetDist} stroke="#4ade80" strokeWidth="3.5" className="liquid-green-flow" />}
                  {showSilver && <line x1={fromNode.x} y1={fromNode.y} x2={toNode.x} y2={toNode.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />}
                </g>
              );
            })}
            {extraSilverLines.map(([fromId, toId], idx) => {
              const f = KATHARA_GRID_NODES.find(n => n.id === fromId);
              const t = KATHARA_GRID_NODES.find(n => n.id === toId);
              if (!f || !t) return null;
              return (
                <g key={`extra-silver-${idx}`}>
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="rgba(203,213,225,0.4)" strokeWidth="3" />
                  <line x1={f.x} y1={f.y} x2={t.x} y2={t.y} stroke="#cbd5e1" strokeWidth="3.5" className="liquid-silver-flow" />
                </g>
              );
            })}
          </g>

          {showLightning && (
            <g className="pointer-events-none">
              <path d="M 75 20 L 95 60 L 55 100 L 75 140" fill="none" className="lightning-bolt" />
              <path d="M 30 140 L 55 170 L 35 200 L 75 240" fill="none" className="lightning-bolt" />
              <path d="M 120 140 L 95 170 L 115 200 L 75 240" fill="none" className="lightning-bolt" />
            </g>
          )}

          {showExplosion && (
            <g transform="translate(75, 140)" className="pointer-events-none">
              <circle r="12" className="fire-burst" />
              <circle r="8" className="fire-burst" style={{ animationDelay: '0.1s' }} />
            </g>
          )}

          {KATHARA_GRID_NODES.map((node, nodeIdx) => {
            const isFilter = node.id > 12;
            const isHighlighted = highlightedNodes.includes(node.id);
            const displayLabelIdx = isFilter ? -1 : getDisplayIdx(nodeIdx, labelOffset, activeMode);
            const rawLabel = isFilter ? '' : labels[displayLabelIdx];

            const filterFullLabel = node.id === 13 ? '△108⚡' : node.id === 14 ? '🔥103🐟' : node.id === 15 ? '⚫110🌳' : null;

            const labelParts = rawLabel ? rawLabel.split('|').map(p => p.trim()) : [];
            const hasMultiple = labelParts.length > 1;
            const isSpineNode = node.x === 75 && node.id <= 12; 
            const isLeftSide = node.x < 75;

            return (
              <g key={node.id} className="transition-all duration-500">
                {isFilter ? (
                  <g>
                    {isHighlighted && <rect x={node.x-28} y={node.y-12} width="56" height="24" rx="4" fill="rgba(6,182,212,0.15)" className="animate-pulse" />}
                    <rect x={node.x-25} y={node.y-10} width="50" height="20" rx="3" className={`filter-junction ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#06b6d4' }} />
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#0891b2"} className="font-mono tracking-tighter" style={{ pointerEvents: 'none' }}>
                      {filterFullLabel}
                    </text>
                  </g>
                ) : (
                  <g>
                    <rect x={node.x-14} y={node.y-14} width="28" height="28" rx="6" className={`junction-box ${isHighlighted ? 'active-junction node-glow' : ''}`} style={{ color: '#fff' }} />
                    {isHighlighted && <circle cx={node.x} cy={node.y} r={22} fill="url(#activeGrad)" opacity="0.1" className="animate-pulse" />}
                    <text x={node.x} y={node.y} textAnchor="middle" dy=".3em" fontSize="8" fontWeight="black" fill={isHighlighted ? "#fff" : "#555"}>{node.id}</text>
                    {rawLabel && (
                      <g className="pointer-events-none">
                         {isSpineNode && hasMultiple ? (
                          <>
                            <rect x={node.x - 76} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x - 22} y={node.y} textAnchor="end" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[0]}</text>
                            <rect x={node.x + 18} y={node.y - 9} width="58" height="18" rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                            <text x={node.x + 22} y={node.y} textAnchor="start" dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">{labelParts[1]}</text>
                          </>
                         ) : (
                          <g>
                             <rect x={isLeftSide ? node.x - 76 : node.x + 18} y={node.y - (hasMultiple ? 14 : 9)} width="58" height={hasMultiple ? 28 : 18} rx="4" fill="rgba(0,0,0,0.85)" stroke={isHighlighted ? "rgba(34,211,238,0.4)" : "rgba(255,255,255,0.05)"} />
                             <text x={isLeftSide ? node.x - 22 : node.x + 22} y={node.y} textAnchor={isLeftSide ? "end" : "start"} dominantBaseline="middle" fontSize="7.5" fontWeight="900" fill={isHighlighted ? "#fff" : "#4ade80"} className="font-mono uppercase tracking-tighter">
                               {hasMultiple ? (<><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="-0.5em">{labelParts[0]}</tspan><tspan x={isLeftSide ? node.x - 22 : node.x + 22} dy="1.1em">{labelParts[1]}</tspan></>) : rawLabel}
                             </text>
                          </g>
                         )}
                      </g>
                    )}
                  </g>
                )}
              </g>
            );
          })}
        </svg>
      </div>
    );
  };

  return (
    <div className="fixed inset-0 z-[200] flex flex-col lg:flex-row bg-[#02040a] animate-in fade-in zoom-in duration-500 overflow-y-auto lg:overflow-hidden no-scrollbar">
      <aside className="w-full lg:w-[420px] p-6 lg:p-8 lg:h-full lg:overflow-y-auto border-b lg:border-r border-white/10 flex flex-col space-y-4 md:space-y-6 bg-black/40 backdrop-blur-xl shrink-0 custom-scrollbar">
        <div className="flex justify-between items-start shrink-0">
          <div className="space-y-1">
            <h2 className="text-xl md:text-2xl font-black text-white tracking-tighter uppercase italic leading-tight">
              Photosynthesis:
              <span className="block text-[10px] md:text-sm font-bold tracking-widest text-cyan-400 mt-1 not-italic">
                Harvesting Love and Intelligence in Form
              </span>
            </h2>
            <div className="flex flex-wrap gap-1.5 mt-2">
               {[0, 1, 2, 3].map(n => (
                 <button key={n} onClick={() => handlePreset(n)} className={`w-8 h-8 md:w-9 md:h-9 rounded-lg border font-black text-[9px] md:text-[10px] transition-all ${n === 0 ? 'bg-white/5 border-white/10 text-gray-500' : 'bg-cyan-950/20 border-cyan-500/30 text-cyan-400 hover:bg-cyan-500 hover:text-black'}`}>
                   {n === 0 ? 'CLR' : `P${n}`}
                 </button>
               ))}
               <button onClick={() => handleSyncFromWheel('full')} className="px-2 md:px-3 h-8 md:h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[9px] md:text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 1</button>
               <button onClick={() => handleSyncFromWheel('title')} className="px-2 md:px-3 h-8 md:h-9 rounded-lg border border-emerald-500/30 bg-emerald-950/20 text-emerald-400 font-black text-[9px] md:text-[10px] hover:bg-emerald-500 hover:text-black transition-all">SYNC 2</button>
            </div>
          </div>
          <button onClick={onClose} className="p-2 md:p-3 rounded-2xl bg-white/5 text-gray-400 hover:text-white transition-all hover:bg-white/10 shrink-0">
            <svg xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 md:h-6 md:w-6" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
        </div>

        <div className="space-y-3 md:space-y-4">
          {labels.map((label, idx) => {
            let mappedNodeId = -1;
            for(let ni=0; ni<12; ni++) {
              if(getDisplayIdx(ni, labelOffset, activeMode) === idx) {
                mappedNodeId = ni + 1;
                break;
              }
            }
            const isCurrentlyActive = highlightedNodes.includes(mappedNodeId);

            return (
              <div key={idx} className={`group relative p-0.5 transition-all duration-300 ${isCurrentlyActive ? 'scale-[1.01] md:scale-[1.02]' : ''}`}>
                <div className="flex justify-between items-end mb-1 px-1">
                  <label className="text-[8px] md:text-[9px] text-gray-500 uppercase tracking-widest font-black block">Leaf {idx + 1}</label>
                </div>
                <input 
                  type="text" value={label} onChange={(e) => updateLabel(idx, e.target.value)} placeholder={`Terminal input ${idx + 1}...`}
                  className={`w-full bg-white/5 border rounded-lg md:rounded-xl px-3 py-2 md:px-4 md:py-3 text-xs md:text-sm font-medium focus:bg-cyan-950/10 outline-none transition-all placeholder-gray-800 ${isCurrentlyActive ? 'border-cyan-500/50 text-white' : 'border-white/5 text-cyan-50/70'}`}
                />
              </div>
            );
          })}
        </div>

        <div className="pt-4 md:pt-6 border-t border-white/5 space-y-3 md:space-y-4 shrink-0 pb-6 bg-black/20 -mx-6 md:-mx-8 px-6 md:px-8">
          <div className="flex justify-between items-baseline px-1">
            <h3 className="text-[10px] md:text-xs font-black text-gray-500 uppercase tracking-[0.2em]">Flow of Life</h3>
            <span className="font-mono text-[10px] md:text-[11px] text-cyan-500 px-2 py-0.5 rounded bg-cyan-950/30">Phase: {labelOffset + 1}</span>
          </div>
          <div className="flex p-1 bg-white/5 rounded-xl md:rounded-2xl gap-1">
            <button onClick={() => { setActiveMode('linear'); setIsCycling(false); }} className={`flex-1 py-2 md:py-3 rounded-lg md:rounded-xl text-[9px] md:text-[10px] font-black tracking-widest transition-all ${activeMode === 'linear' ? 'bg-cyan-500 text-black shadow-lg shadow-cyan-500/20' : 'text-gray-400'}`}>LINEAR</button>
            <button onClick={() => { setActiveMode('bifurcation'); setIsCycling(false); }} className={`flex-1 py-2 md:py-3 rounded-lg md:rounded-xl text-[9px] md:text-[10px] font-black tracking-widest transition-all ${activeMode === 'bifurcation' ? 'bg-fuchsia-600 text-white shadow-lg shadow-fuchsia-600/20' : 'text-gray-400'}`}>BIFURCATE</button>
          </div>
          <div className="grid grid-cols-2 gap-2 md:gap-3">
            <button onClick={() => handleShift('down')} className="bg-white/5 hover:bg-cyan-500/10 py-3 md:py-4 rounded-xl md:rounded-2xl border border-white/5 text-base md:text-lg font-black tracking-widest transition-all uppercase">-</button>
            <button onClick={() => handleShift('up')} className="bg-white/5 hover:bg-cyan-500/10 py-3 md:py-4 rounded-xl md:rounded-2xl border border-white/5 text-base md:text-lg font-black tracking-widest transition-all uppercase">+</button>
          </div>
          <button onClick={() => setIsCycling(!isCycling)} className={`w-full py-3 md:py-4 rounded-xl md:rounded-2xl border font-black text-[10px] md:text-[11px] tracking-[0.2em] transition-all uppercase ${isCycling ? 'bg-red-600 text-white shadow-xl' : 'bg-cyan-600/10 text-cyan-400 border-cyan-500/20 hover:border-cyan-500/50'}`}>
            {isCycling ? 'Stop Stream' : `Animate Stream`}
          </button>
        </div>
      </aside>

      <main className="flex-1 w-full flex items-center justify-center p-4 lg:p-8 lg:h-full lg:overflow-hidden">
        <div className="w-full h-full max-w-4xl flex items-center justify-center">
          {renderDiagram()}
        </div>
      </main>

      <style>{`
        .custom-scrollbar::-webkit-scrollbar { width: 4px; }
        .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
        .custom-scrollbar::-webkit-scrollbar-thumb { background: rgba(6, 182, 212, 0.15); border-radius: 10px; }
        .custom-scrollbar::-webkit-scrollbar-thumb:hover { background: rgba(6, 182, 212, 0.3); }
        .no-scrollbar::-webkit-scrollbar { display: none; }
        .no-scrollbar { -ms-overflow-style: none; scrollbar-width: none; }
      `}</style>
    </div>
  );
};

export default TreeOfLifeMode;

import React, { useMemo, useState, useEffect, useRef, useLayoutEffect } from 'react';
import { createPortal } from 'react-dom';
import { KATHARA_CLOCK_POINTS, KATHARA_GRID_NODES, KATHARA_GRID_LINES, TOTAL_VERSES, TOTAL_SLICES, BUBBLE_BLOCK_MAPPING_RAW } from '../constants.ts';
import { getVerseAddressFromGlobalIndex, getGlobalVerseIndex } from '../utils.ts';
import { ShuffleIcon } from './Icons.tsx';

interface TreeOfVerseProps {
  rotation: number;
  onVerseSelect: (surah: number, ayah: number) => void;
  onBulkExport: (verseIds: string[]) => void;
}

const TREE_LABELS = [
    'Awakening', 'Assertion', 'Disruption', 
    'Constriction', 'Refinement', 'Submission', 
    'Restoration', 'Servanthood', 'Sacrifice', 
    'Witness', 'Ascension', 'Radiance'
];

export const TreeOfVerse: React.FC<TreeOfVerseProps> = ({ rotation, onVerseSelect, onBulkExport }) => {
    const listRef = useRef<HTMLDivElement>(null);
    const floatingRef = useRef<HTMLDivElement>(null);
    const [rootVerse] = useState({ surah: 1, ayah: 1 });
    const [isDesktop, setIsDesktop] = useState(typeof window !== 'undefined' ? window.innerWidth >= 1024 : false);
    const portalRoot = typeof document !== 'undefined' ? document.getElementById('kathara-portal-root') : null;

    // Track local input values to allow typing without immediate re-renders
    const [localInputs, setLocalInputs] = useState<string[][]>([]);

    useEffect(() => {
        const handleResize = () => setIsDesktop(window.innerWidth >= 1024);
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    useLayoutEffect(() => {
        if (!isDesktop) return;
        let rafId: number;
        const updatePosition = () => {
            const listEl = listRef.current;
            const floatingEl = floatingRef.current;
            const scrollContainer = document.getElementById('side-panel-scroll-container');

            if (floatingEl && scrollContainer) {
                const containerRect = scrollContainer.getBoundingClientRect();
                const diagramWidth = 220;
                // Move position higher by decreasing the offset from 340 to 220
                const x = containerRect.left - diagramWidth + 10; 
                const y = containerRect.top + 220; 

                floatingEl.style.transform = `translate3d(${x}px, ${y}px, 0)`;
                floatingEl.style.width = `${diagramWidth}px`;
                floatingEl.style.height = `400px`;

                if (listEl) {
                    const listRect = listEl.getBoundingClientRect();
                    // Sync visibility with the section's visibility in the viewport
                    const isSectionVisible = listRect.bottom > containerRect.top && listRect.top < containerRect.bottom;
                    floatingEl.style.opacity = isSectionVisible ? '1' : '0';
                    floatingEl.style.pointerEvents = isSectionVisible ? 'auto' : 'none';
                }
            }
        };
        const loop = () => { updatePosition(); rafId = requestAnimationFrame(loop); };
        rafId = requestAnimationFrame(loop);
        return () => cancelAnimationFrame(rafId);
    }, [isDesktop]);

    const verseScalingFactor = TOTAL_VERSES / TOTAL_SLICES;
    const rotationOffset = (rotation / 360) * TOTAL_VERSES;

    const trines = useMemo(() => {
        const rootIndex = getGlobalVerseIndex(rootVerse.surah, rootVerse.ayah);
        const baseIndex = rootIndex - rotationOffset;

        return KATHARA_CLOCK_POINTS.map((pointValue) => {
            const pointOffset = (pointValue - 1) * verseScalingFactor;
            const startIdx = Math.round(baseIndex + pointOffset);

            return [0, 1, 2].map(offset => {
                const globalIdx = ((startIdx + offset - 1) % TOTAL_VERSES + TOTAL_VERSES) % TOTAL_VERSES + 1;
                return getVerseAddressFromGlobalIndex(globalIdx);
            });
        });
    }, [rootVerse, rotation, verseScalingFactor, rotationOffset]);

    // Sync local inputs when trines change (from external source like root or rotation)
    useEffect(() => {
        setLocalInputs(trines.map(trine => trine.map(v => `${v.surah}:${v.ayah}`)));
    }, [trines]);

    const updateRootFromTarget = (nodeIdx: number, vIdx: number, targetSurah: number, targetAyah: number) => {
        // Functionality kept internal if user manually edits the trine input fields
        const targetGlobalIdx = getGlobalVerseIndex(targetSurah, targetAyah);
        const pointValue = KATHARA_CLOCK_POINTS[nodeIdx];
        const pointOffset = (pointValue - 1) * verseScalingFactor;

        let calculatedRootIndex = Math.round(targetGlobalIdx + rotationOffset - pointOffset - vIdx);
        calculatedRootIndex = ((calculatedRootIndex - 1) % TOTAL_VERSES + TOTAL_VERSES) % TOTAL_VERSES + 1;

        // This used to set rootVerse, but since manual controls are gone, we'll keep the trine editing reactive locally if needed
        // For now, root remains 1:1 unless we decide to restore dynamic seeding
    };

    const handleLocalInputChange = (nodeIdx: number, vIdx: number, value: string) => {
        const newLocal = [...localInputs];
        newLocal[nodeIdx][vIdx] = value.replace(/[^0-9:]/g, '');
        setLocalInputs(newLocal);

        const parts = value.split(':');
        if (parts.length === 2) {
            const s = parseInt(parts[0], 10);
            const a = parseInt(parts[1], 10);
            if (!isNaN(s) && !isNaN(a) && s >= 1 && s <= 114) {
                const maxAyahs = BUBBLE_BLOCK_MAPPING_RAW[s as keyof typeof BUBBLE_BLOCK_MAPPING_RAW] || 0;
                if (a >= 1 && a <= maxAyahs) {
                    updateRootFromTarget(nodeIdx, vIdx, s, a);
                }
            }
        }
    };

    // Stretched coordinate mapping
    const transformY = (y: number) => 20 + (y - 20) * 1.15;

    const renderDiagram = () => (
        <div className="flex justify-center w-full h-full p-2">
            <svg viewBox="0 0 150 320" width="100%" height="100%" aria-hidden="true" className="drop-shadow-[0_0_15px_rgba(6,182,212,0.4)]">
                <style>{`
                    @keyframes pulse-cyan { 0% { opacity: 0.3; } 50% { opacity: 0.7; } 100% { opacity: 0.3; } }
                    .tree-line { animation: pulse-cyan 4s infinite ease-in-out; }
                `}</style>
                <g strokeWidth="1.3">
                    {KATHARA_GRID_LINES.filter(l => l.from <= 12 && l.to <= 12).map((line, index) => {
                        const fromNode = KATHARA_GRID_NODES.find(n => n.id === line.from);
                        const toNode = KATHARA_GRID_NODES.find(n => n.id === line.to);
                        if (!fromNode || !toNode) return null;
                        return <line key={index} x1={fromNode.x} y1={transformY(fromNode.y)} x2={toNode.x} y2={transformY(toNode.y)} stroke={index % 2 === 0 ? "#06b6d4" : "#d946ef"} className="tree-line" />;
                    })}
                </g>
                {KATHARA_GRID_NODES.slice(0, 12).map((node, index) => {
                    const firstVerse = trines[index][0];
                    const ty = transformY(node.y);
                    return (
                        <g key={node.id}>
                            <circle cx={node.x} cy={ty} r={11} fill="#000" stroke="#06b6d4" strokeWidth="1.5" />
                            <text x={node.x} y={ty} textAnchor="middle" dy=".3em" fontSize="8.5" fontWeight="bold" fill="#fff" style={{ textShadow: '0 0 4px #06b6d4' }}>
                                {firstVerse.surah}:{firstVerse.ayah}
                            </text>
                            <text x={node.x} y={ty - 14} textAnchor="middle" fontSize="6.5" fill="#94a3b8" fontWeight="bold" className="uppercase" style={{ textShadow: '0 0 2px #000' }}>
                                {TREE_LABELS[index]}
                            </text>
                        </g>
                    );
                })}
            </svg>
        </div>
    );

    return (
        <div className="pt-4 animate-in fade-in slide-in-from-right duration-500">
            <div className="flex justify-between items-center mb-6">
                <h2 className="text-xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-cyan-300 to-fuchsia-400 tracking-wider">TREE OF VERSE</h2>
                <button onClick={() => onBulkExport(trines.flat().map(v => `${v.surah}:${v.ayah}`))} className="text-[10px] px-2 py-1 bg-cyan-900/40 border border-cyan-500/30 rounded hover:bg-cyan-500/30 transition-colors text-cyan-100">Bulk Export (36)</button>
            </div>

            {!isDesktop ? (
                <div className="my-4 h-[420px] bg-black/20 rounded-xl border border-white/5">{renderDiagram()}</div>
            ) : (
                portalRoot && createPortal(
                    <div ref={floatingRef} className="transition-opacity duration-300" style={{ position: 'fixed', top: 0, left: 0, zIndex: 5, willChange: 'transform' }}>
                        {renderDiagram()}
                    </div>,
                    portalRoot
                )
            )}

            <div ref={listRef} className="space-y-3 mt-4">
                {trines.map((trine, nodeIdx) => (
                    <div key={nodeIdx} className="bg-gray-900/30 border border-white/5 rounded-lg p-3 hover:border-cyan-500/20 transition-all group">
                        <div className="flex justify-between items-center mb-2">
                            <span className="text-[10px] font-bold text-gray-500 tracking-widest uppercase">{nodeIdx + 1}. {TREE_LABELS[nodeIdx]}</span>
                        </div>
                        <div className="grid grid-cols-3 gap-1.5">
                            {trine.map((v, vIdx) => (
                                <div 
                                    key={vIdx} 
                                    className="relative flex flex-col items-center py-1 px-1.5 bg-black/60 border border-white/10 rounded group/input focus-within:border-cyan-500/50 focus-within:bg-cyan-900/10 transition-all"
                                >
                                    <input 
                                        type="text"
                                        value={localInputs[nodeIdx]?.[vIdx] || ''}
                                        onChange={(e) => handleLocalInputChange(nodeIdx, vIdx, e.target.value)}
                                        onDoubleClick={() => onVerseSelect(v.surah, v.ayah)}
                                        className="bg-transparent border-none p-0 font-mono text-cyan-400 text-xs glow-text text-center w-full focus:ring-0 focus:outline-none cursor-text"
                                        placeholder="S:A"
                                        title="Double click to view verse"
                                    />
                                    <span className="text-[7px] opacity-40 uppercase pointer-events-none">V{vIdx + 1}</span>
                                </div>
                            ))}
                        </div>
                    </div>
                ))}
            </div>

            <style>{`.glow-text { text-shadow: 0 0 5px currentColor; }`}</style>
        </div>
    );
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { TOTAL_SLICES, CHAPTER_DETAILS, MUQATTAT_CHAPTERS, MUQATTAT_LETTERS, CENTRAL_GEOMETRY_POINTS } from '../constants.ts';
import { TAFSIR_YOUTUBE_VIDEO_IDS, RECITATION_YOUTUBE_VIDEO_IDS, ENGLISH_RECITATION_YOUTUBE_VIDEO_IDS } from '../youtubeData.ts';
import { getSliceAtPoint, getChapterIcon } from '../utils.ts';
import { PlaylistType } from '../types.ts';
import PlaylistButtons from './PlaylistButtons.tsx';
import CustomAnimationControls from './CustomAnimationControls.tsx';
import ChapterGeometry from './ChapterGeometry.tsx';
import MarkerAlignment from './MarkerAlignment.tsx';
import { KatharaClockAlignment, SephirotAlignment } from './SecretPatternAnimation.tsx';
import { TreeOfVerse } from './TreeOfVerse.tsx';
import { PieceOfBakara } from './PieceOfBakara.tsx';

interface SidePanelProps {
  rotation: number;
  iconDialRotation: number;
  setRotation: (rotation: number | ((prev: number) => number)) => void;
  setIconDialRotation: (rotation: number | ((prev: number) => number)) => void;
  showTooltip: (e: React.MouseEvent, surah: number, verse: number, color: string) => void;
  hideTooltip: () => void;
  isSecretModeActive: boolean;
  isTreeOfVerseActive: boolean;
  isPieceOfBakaraActive: boolean;
  secretEmojiShift: number;
  isLowResourceMode: boolean;
  onVerseSelect: (surah: number, ayah: number) => void;
  onBulkExport: (verseIds: string[]) => void;
  bakaraSpineIndex: number;
  setBakaraSpineIndex: (index: number) => void;
}

const SidePanel: React.FC<SidePanelProps> = ({ rotation, iconDialRotation, setRotation, setIconDialRotation, showTooltip, hideTooltip, isSecretModeActive, isTreeOfVerseActive, isPieceOfBakaraActive, secretEmojiShift, isLowResourceMode, onVerseSelect, onBulkExport, bakaraSpineIndex, setBakaraSpineIndex }) => {
  const [customSequence, setCustomSequence] = useState('');
  const [animationMode, setAnimationMode] = useState<'play' | 'step' | 'off'>('off');
  const [animationIndex, setAnimationIndex] = useState(0);

  const animationFrameId = useRef<number | null>(null);
  const animationTimeoutId = useRef<number | null>(null);
  const rotationRef = useRef(rotation);

  useEffect(() => {
    rotationRef.current = rotation;
  }, [rotation]);

  const handleStep = useCallback((direction: 'forward' | 'backward') => {
      if (!customSequence.trim()) return;
      setAnimationMode('step');
      if (direction === 'forward') {
          setAnimationIndex(prev => prev + 1);
      } else {
          setAnimationIndex(prev => Math.max(0, prev - 1));
      }
  }, [customSequence]);

  useEffect(() => {
      const handleKeyDown = (event: KeyboardEvent) => {
          if (document.activeElement?.tagName === 'INPUT') return;
          if (event.key.toLowerCase() === 'q') {
              event.preventDefault();
              handleStep('backward');
          } else if (event.key.toLowerCase() === 'e') {
              event.preventDefault();
              handleStep('forward');
          }
      };
      window.addEventListener('keydown', handleKeyDown);
      return () => window.removeEventListener('keydown', handleKeyDown);
  }, [handleStep]);

  const animationSequence = useMemo(() => {
    return (customSequence.match(/\d+/g) || [])
        .map(s => parseInt(s, 10))
        .filter(n => !isNaN(n) && n >= 1 && n <= TOTAL_SLICES);
  }, [customSequence]);


  useEffect(() => {
    const cleanup = () => {
        if (animationFrameId.current) cancelAnimationFrame(animationFrameId.current);
        if (animationTimeoutId.current) clearTimeout(animationTimeoutId.current);
    };

    if (animationMode === 'off') {
        cleanup();
        return;
    }

    const sequence = animationSequence;

    if (sequence.length === 0) {
        setAnimationMode('off');
        return;
    }

    let targetIndex = animationIndex;
    if (animationMode === 'play') {
      targetIndex = animationIndex % sequence.length;
    }

    if (targetIndex >= sequence.length || targetIndex < 0) {
        setAnimationMode('off');
        return;
    }

    const currentTargetSliceId = sequence[targetIndex];
    const sliceAngle = 360 / TOTAL_SLICES;
    const targetRotation = -(currentTargetSliceId - 1) * sliceAngle;

    const startRotation = rotationRef.current;

    const startSliceId = getSliceAtPoint(1, startRotation).id;
    const distance = Math.abs(currentTargetSliceId - startSliceId);
    const wrappedDistance = Math.min(distance, TOTAL_SLICES - distance);

    const BASE_DURATION = 500;
    const DURATION_PER_SLICE = 25;
    const DURATION = BASE_DURATION + wrappedDistance * DURATION_PER_SLICE;
    const PAUSE_DURATION = 700;

    let startTime: number | null = null;
    const easeInOutCubic = (t: number) => t < 0.5 ? 4 * t * t * t : 1 - Math.pow(-2 * t + 2, 3) / 2;

    let rotationDiff = targetRotation - startRotation;
    if (rotationDiff > 180) {
        rotationDiff -= 360;
    } else if (rotationDiff < -180) {
        rotationDiff += 360;
    }

    const animate = (timestamp: number) => {
        if (!startTime) startTime = timestamp;
        const elapsed = timestamp - startTime;
        const progress = Math.min(elapsed / DURATION, 1);
        const easedProgress = easeInOutCubic(progress);

        const newRotation = startRotation + rotationDiff * easedProgress;
        setRotation(newRotation);

        if (progress < 1) {
            animationFrameId.current = requestAnimationFrame(animate);
        } else {
            setRotation(targetRotation);
            if (animationMode === 'play') {
                animationTimeoutId.current = window.setTimeout(() => {
                    setAnimationIndex(prev => prev + 1);
                }, PAUSE_DURATION);
            } else if (animationMode === 'step') {
                setAnimationMode('off');
            }
        }
    };

    animationFrameId.current = requestAnimationFrame(animate);

    return cleanup;
  }, [animationMode, animationIndex, animationSequence, setRotation]);


  const createPlaylist = (type: PlaylistType, chapterIds: number[]) => {
    const videoSource = 
        type === 'recitation' ? RECITATION_YOUTUBE_VIDEO_IDS : 
        type === 'tafsir' ? TAFSIR_YOUTUBE_VIDEO_IDS :
        ENGLISH_RECITATION_YOUTUBE_VIDEO_IDS;

    const videoIds = chapterIds
      .map(id => videoSource[id - 1])
      .filter(id => id);

    if (videoIds.length > 0) {
      const url = `https://www.youtube.com/watch_videos?video_ids=${videoIds.join(',')}`;
      window.open(url, '_blank', 'noopener,noreferrer');
    } else {
      alert("Videos for this playlist are currently unavailable.");
    }
  };

  const handleWatchSequence = (type: PlaylistType) => {
    const chapterIds = CENTRAL_GEOMETRY_POINTS.map(pointValue => getSliceAtPoint(pointValue, rotation).id);
    createPlaylist(type, chapterIds);
  };

  const handleSliderChange = (event: React.ChangeEvent<HTMLInputElement>) => {
    setAnimationMode('off');
    const val = Number(event.target.value);

    if (isPieceOfBakaraActive) {
      setBakaraSpineIndex(val);
    } else {
      const sliceAngle = 360 / TOTAL_SLICES;
      const newRotation = -(val - 1) * sliceAngle;
      setRotation(newRotation);
    }
  };

  const currentSliceData = getSliceAtPoint(1, rotation);
  const currentSliceId = currentSliceData.id;
  // Safer lookup to avoid crash if CHAPTER_DETAILS array is inconsistent
  const chapterInfo = CHAPTER_DETAILS.find(c => c.number === currentSliceId);

  if (!chapterInfo) return <aside className="w-full lg:w-96 bg-black/30 lg:backdrop-blur-sm p-6 border-t lg:border-l lg:border-t-0 border-gray-700/50 flex flex-col space-y-4">Loading...</aside>;

  const isCurrentSliceMuqattat = MUQATTAT_CHAPTERS.has(currentSliceId);
  const muqattatLetters = MUQATTAT_LETTERS.get(currentSliceId);
  const iconSrc = getChapterIcon(chapterInfo.revelationType);

  const isAnalyticalMode = isTreeOfVerseActive || isPieceOfBakaraActive;

  return (
    <aside 
        id="side-panel-scroll-container"
        className="w-full lg:w-96 bg-black/30 lg:backdrop-blur-sm p-6 border-t lg:border-l lg:border-t-0 border-gray-700/50 flex flex-col space-y-4 lg:overflow-y-auto scroll-smooth"
    >
      {/* Sticky identification and playlist header - Hidden in Piece of Heifer and Tree of Verse modes */}
      {!isAnalyticalMode && (
        <div className="sticky top-0 z-40 -mx-6 px-6 py-4 bg-black/85 backdrop-blur-xl border-b border-cyan-500/30 shadow-2xl transition-all duration-300">
            {/* Top Navigation Row */}
            <div className="flex justify-between items-center mb-4">
                <h2 className="text-xl font-bold text-cyan-300 tracking-wider">▼🕋▲</h2>
                <PlaylistButtons onWatch={handleWatchSequence} />
            </div>
            <div className="w-full h-px bg-cyan-300/30 mb-4"></div>

            {/* Chapter Identification Info */}
            <div className="flex justify-between items-start lg:min-h-[80px]">
                <div className="font-semibold text-gray-200 pr-2">
                    <div className="flex items-baseline gap-x-2">
                        <img src={iconSrc} alt={chapterInfo.revelationType} title={chapterInfo.revelationType} className="w-5 h-5" />
                        <span className={`text-lg text-cyan-300 ${isCurrentSliceMuqattat ? 'muqattat-glow' : ''}`}>
                            {chapterInfo.number}. {chapterInfo.englishName}
                        </span>
                        {muqattatLetters && (
                            <span 
                                className={`font-mono text-xl ${isCurrentSliceMuqattat ? 'muqattat-glow' : 'text-white'}`}
                                dir="rtl"
                            >
                                {muqattatLetters.join(' · ')}
                            </span>
                        )}
                    </div>
                    <div className="flex gap-x-2 items-center">
                        <span className="text-base font-normal italic text-gray-400">
                            ({chapterInfo.transliteration})
                        </span>
                    </div>
                </div>
                <button
                    onClick={() => setRotation(0)}
                    className="bg-gray-600 hover:bg-cyan-700 text-white font-bold py-1 px-3 rounded text-sm transition-colors duration-200 flex-shrink-0 mt-1 shadow-lg"
                    aria-label="Reset rotation"
                >
                    Reset
                </button>
            </div>

            {/* Global Chapter Slider */}
            <input
                id="rotation-slider"
                type="range"
                min="1"
                max={TOTAL_SLICES}
                step="1"
                value={currentSliceId}
                onChange={handleSliderChange}
                className="w-full h-2 bg-gray-700 rounded-lg appearance-none cursor-pointer mt-4"
            />
        </div>
      )}

      {/* Non-sticky analytical components section */}
      <div className={!isAnalyticalMode ? "space-y-6 pt-2" : ""}>

         {!isAnalyticalMode && (
            <div className="mb-6">
                <CustomAnimationControls 
                   customSequence={customSequence}
                   setCustomSequence={setCustomSequence}
                   animationMode={animationMode}
                   setAnimationMode={setAnimationMode}
                   setAnimationIndex={setAnimationIndex}
                   createPlaylist={createPlaylist}
                />
            </div>
         )}

         {isTreeOfVerseActive ? (
            <TreeOfVerse 
                rotation={rotation} 
                onVerseSelect={onVerseSelect}
                onBulkExport={onBulkExport}
            />
         ) : isPieceOfBakaraActive ? (
            <PieceOfBakara 
                onVerseSelect={onVerseSelect}
                onBulkExport={onBulkExport}
                bakaraSpineIndex={bakaraSpineIndex}
                setBakaraSpineIndex={setBakaraSpineIndex}
            />
         ) : (
            <>
                <ChapterGeometry 
                    rotation={rotation}
                    isLowResourceMode={isLowResourceMode}
                />

                <MarkerAlignment 
                    isSecretModeActive={isSecretModeActive}
                    rotation={rotation}
                    iconDialRotation={iconDialRotation}
                    setIconDialRotation={setIconDialRotation}
                    secretEmojiShift={secretEmojiShift}
                    setCustomSequence={setCustomSequence}
                    setAnimationMode={setAnimationMode}
                    createPlaylist={createPlaylist}
                />
                {isSecretModeActive && (
                    <>
                        <KatharaClockAlignment
                            rotation={rotation}
                            createPlaylist={createPlaylist}
                            setCustomSequence={setCustomSequence}
                            setAnimationMode={setAnimationMode}
                        />
                        <SephirotAlignment
                            rotation={rotation}
                            createPlaylist={createPlaylist}
                            setCustomSequence={setCustomSequence}
                            setAnimationMode={setAnimationMode}
                        />
                    </>
                )}
            </>
         )}
      </div>
    </aside>
  );
};

export default SidePanel;
